import type { Question } from '@/types';

// ============================================================================
// HOTEL GENERAL MANAGER — PROFESSIONAL QUESTIONS
// ============================================================================

export const hospHgmProfessionalQuestions: Question[] = [
  // Hotel Operations — multiple-choice
  { id: 'hosp-hgm-prof-1', profileId: 'hotel-general-manager', categoryId: 'hosp-hgm-professional', competencyId: 'hosp-hgm-hotel-operations', type: 'multiple-choice', content: { es: 'Su hotel de 250 habitaciones experimenta una ocupación del 95% durante temporada alta. Housekeeping reporta que solo puede preparar 180 habitaciones por turno y el check-in comienza a las 15:00. A las 14:00 tiene 60 habitaciones pendientes de limpieza con huéspedes llegando. ¿Cuál es su estrategia operativa inmediata?', en: 'Your 250-room hotel is experiencing 95% occupancy during peak season. Housekeeping reports it can only prepare 180 rooms per shift and check-in starts at 3:00 PM. At 2:00 PM you have 60 rooms still pending cleaning with guests arriving. What is your immediate operational strategy?', fr: 'Votre hôtel de 250 chambres connaît un taux d\'occupation de 95% en haute saison. Le service d\'entretien ne peut préparer que 180 chambres par quart de travail et le check-in commence à 15h00. À 14h00, il reste 60 chambres à nettoyer avec des clients qui arrivent. Quelle est votre stratégie opérationnelle immédiate ?' }, options: [{ id: 'a', text: { es: 'Activar protocolo de emergencia: reasignar personal de otras áreas a housekeeping, priorizar habitaciones por hora de llegada confirmada, ofrecer early check-in en las ya listas, habilitar zona de espera con servicio de bienvenida y comunicar proactivamente a los huéspedes pendientes con horario estimado', en: 'Activate emergency protocol: reassign staff from other areas to housekeeping, prioritize rooms by confirmed arrival time, offer early check-in for ready rooms, set up a waiting area with welcome service, and proactively communicate with pending guests with estimated times', fr: 'Activer le protocole d\'urgence : réaffecter du personnel d\'autres services à l\'entretien, prioriser les chambres par heure d\'arrivée confirmée, offrir un check-in anticipé pour les chambres prêtes, installer une zone d\'attente avec service d\'accueil et communiquer proactivement avec les clients' }, value: 100 }, { id: 'b', text: { es: 'Pedir a recepción que informe a los huéspedes que el check-in se retrasará hasta las 16:00', en: 'Ask front desk to inform guests that check-in will be delayed until 4:00 PM', fr: 'Demander à la réception d\'informer les clients que le check-in sera retardé jusqu\'à 16h00' }, value: 25 }, { id: 'c', text: { es: 'Contratar personal temporal de limpieza de emergencia a través de una agencia', en: 'Hire temporary emergency cleaning staff through an agency', fr: 'Embaucher du personnel de nettoyage temporaire d\'urgence via une agence' }, value: 40 }, { id: 'd', text: { es: 'Ofrecer upgrades gratuitos a los huéspedes cuyas habitaciones no estén listas a cambio de esperar', en: 'Offer free upgrades to guests whose rooms are not ready in exchange for waiting', fr: 'Offrir des surclassements gratuits aux clients dont les chambres ne sont pas prêtes en échange d\'une attente' }, value: 50 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  // Revenue Management — multiple-choice
  { id: 'hosp-hgm-prof-2', profileId: 'hotel-general-manager', categoryId: 'hosp-hgm-professional', competencyId: 'hosp-hgm-revenue-management', type: 'multiple-choice', content: { es: 'El análisis de su revenue manager muestra que el ADR (tarifa diaria promedio) del hotel ha caído un 12% en los últimos 6 meses mientras que la competencia directa ha subido un 5%. Su ocupación se mantiene en 78%. Los canales OTA (Booking, Expedia) representan el 65% de las reservas con comisiones del 18-22%. ¿Cuál es su estrategia de revenue management?', en: 'Your revenue manager\'s analysis shows that the hotel\'s ADR (Average Daily Rate) has dropped 12% in the last 6 months while direct competition has increased by 5%. Your occupancy remains at 78%. OTA channels (Booking, Expedia) represent 65% of bookings with 18-22% commissions. What is your revenue management strategy?', fr: 'L\'analyse de votre revenue manager montre que l\'ADR de l\'hôtel a chuté de 12% en 6 mois tandis que la concurrence directe a augmenté de 5%. Votre taux d\'occupation reste à 78%. Les canaux OTA (Booking, Expedia) représentent 65% des réservations avec des commissions de 18-22%. Quelle est votre stratégie de revenue management ?' }, options: [{ id: 'a', text: { es: 'Implementar estrategia integral: ajustar pricing dinámico basado en demanda real, fortalecer canal directo con programa de fidelización y mejor tarifa garantizada, negociar comisiones OTA por volumen, crear paquetes de valor agregado y segmentar tarifas por tipo de huésped', en: 'Implement a comprehensive strategy: adjust dynamic pricing based on real demand, strengthen direct channel with loyalty program and best rate guarantee, negotiate OTA commissions by volume, create value-added packages, and segment rates by guest type', fr: 'Mettre en œuvre une stratégie intégrale : ajuster la tarification dynamique selon la demande réelle, renforcer le canal direct avec un programme de fidélité et une garantie de meilleur tarif, négocier les commissions OTA par volume, créer des forfaits à valeur ajoutée et segmenter les tarifs par type de client' }, value: 100 }, { id: 'b', text: { es: 'Bajar tarifas un 10% adicional para aumentar la ocupación y compensar con volumen', en: 'Lower rates by an additional 10% to increase occupancy and compensate with volume', fr: 'Baisser les tarifs de 10% supplémentaires pour augmenter l\'occupation et compenser par le volume' }, value: 20 }, { id: 'c', text: { es: 'Salir de las plataformas OTA y enfocarse exclusivamente en reservas directas', en: 'Exit OTA platforms and focus exclusively on direct bookings', fr: 'Quitter les plateformes OTA et se concentrer exclusivement sur les réservations directes' }, value: 30 }, { id: 'd', text: { es: 'Aumentar las tarifas un 15% para igualar a la competencia sin cambiar la estrategia de distribución', en: 'Increase rates by 15% to match the competition without changing the distribution strategy', fr: 'Augmenter les tarifs de 15% pour égaler la concurrence sans changer la stratégie de distribution' }, value: 35 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  // Quality Standards — multiple-choice
  { id: 'hosp-hgm-prof-3', profileId: 'hotel-general-manager', categoryId: 'hosp-hgm-professional', competencyId: 'hosp-hgm-quality-standards', type: 'multiple-choice', content: { es: 'Una inspección sorpresa del departamento de turismo identifica tres no conformidades: (1) registro de temperaturas de alimentos incompleto en 3 de los últimos 7 días, (2) extintores de incendio en dos pisos con fecha de recarga vencida, (3) señalización de salidas de emergencia parcialmente obstruida en el área de eventos. Le dan 30 días para corregir. ¿Cómo procede?', en: 'A surprise inspection by the tourism department identifies three non-conformities: (1) incomplete food temperature logs for 3 of the last 7 days, (2) fire extinguishers on two floors past their recharge date, (3) emergency exit signage partially obstructed in the events area. You have 30 days to correct. How do you proceed?', fr: 'Une inspection surprise du département du tourisme identifie trois non-conformités : (1) registres de températures alimentaires incomplets pour 3 des 7 derniers jours, (2) extincteurs d\'incendie sur deux étages avec date de recharge expirée, (3) signalisation des sorties de secours partiellement obstruée dans l\'espace événementiel. Vous avez 30 jours pour corriger. Comment procédez-vous ?' }, options: [{ id: 'a', text: { es: 'Corregir las tres no conformidades dentro de 48 horas (no esperar 30 días), implementar auditorías internas semanales, capacitar al personal involucrado, nombrar responsables de seguimiento para cada área y documentar todas las acciones correctivas para evidenciar ante el regulador', en: 'Correct all three non-conformities within 48 hours (do not wait 30 days), implement weekly internal audits, train involved staff, assign follow-up owners for each area, and document all corrective actions as evidence for the regulator', fr: 'Corriger les trois non-conformités dans les 48 heures (ne pas attendre 30 jours), mettre en place des audits internes hebdomadaires, former le personnel concerné, nommer des responsables de suivi pour chaque domaine et documenter toutes les actions correctives' }, value: 100 }, { id: 'b', text: { es: 'Delegar la corrección al jefe de mantenimiento y al chef ejecutivo y revisar en 15 días', en: 'Delegate corrections to the maintenance chief and executive chef and review in 15 days', fr: 'Déléguer les corrections au chef de maintenance et au chef exécutif et vérifier dans 15 jours' }, value: 40 }, { id: 'c', text: { es: 'Enfocarse primero en los extintores por ser el riesgo de seguridad más grave y luego abordar los demás', en: 'Focus first on the fire extinguishers as the most serious safety risk and then address the others', fr: 'Se concentrer d\'abord sur les extincteurs comme risque de sécurité le plus grave puis traiter les autres' }, value: 55 }, { id: 'd', text: { es: 'Contratar un consultor externo de calidad para que gestione todas las correcciones', en: 'Hire an external quality consultant to manage all corrections', fr: 'Embaucher un consultant externe en qualité pour gérer toutes les corrections' }, value: 30 }], maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  // Hotel Operations — scale
  { id: 'hosp-hgm-prof-4', profileId: 'hotel-general-manager', categoryId: 'hosp-hgm-professional', competencyId: 'hosp-hgm-hotel-operations', type: 'scale', content: { es: '¿Qué nivel de experiencia tiene gestionando operaciones simultáneas de múltiples departamentos hoteleros (recepción, housekeeping, A&B, mantenimiento, seguridad)?', en: 'What level of experience do you have managing simultaneous operations across multiple hotel departments (front desk, housekeeping, F&B, maintenance, security)?', fr: 'Quel niveau d\'expérience avez-vous dans la gestion simultanée des opérations de plusieurs départements hôteliers (réception, entretien ménager, restauration, maintenance, sécurité) ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Experiencia limitada en gestión multidepartamental', en: 'Limited experience in multi-departmental management', fr: 'Expérience limitée en gestion multidépartementale' }, max: { es: 'Amplia experiencia liderando todos los departamentos de un hotel', en: 'Extensive experience leading all departments of a hotel', fr: 'Vaste expérience dans la direction de tous les départements d\'un hôtel' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  // Revenue Management — scenario
  { id: 'hosp-hgm-prof-5', profileId: 'hotel-general-manager', categoryId: 'hosp-hgm-professional', competencyId: 'hosp-hgm-revenue-management', type: 'scenario', content: { es: 'Usted dirige un hotel resort de 4 estrellas en una zona costera. Un huracán categoría 2 ha sido pronosticado para impactar la región en 5 días, justo durante el puente festivo más importante del año. Tiene 85% de ocupación confirmada (210 de 250 habitaciones) para ese fin de semana. Las aerolíneas ya están emitiendo alertas de vuelo. Algunos huéspedes llaman para cancelar pero la política de cancelación establece un cargo del 100% con menos de 72 horas de anticipación.\nContexto: El año pasado, un huracán similar causó daños menores pero el hotel cerró 3 días por prevención. Su seguro tiene un deducible de USD 50,000. Los ingresos proyectados para ese fin de semana son USD 180,000.', en: 'You manage a 4-star resort hotel in a coastal area. A Category 2 hurricane has been forecast to hit the region in 5 days, right during the most important holiday weekend of the year. You have 85% confirmed occupancy (210 of 250 rooms) for that weekend. Airlines are already issuing flight alerts. Some guests are calling to cancel but the cancellation policy states a 100% charge with less than 72 hours notice.\nContext: Last year, a similar hurricane caused minor damage but the hotel closed for 3 days as a precaution. Your insurance has a USD 50,000 deductible. Projected revenue for that weekend is USD 180,000.', fr: 'Vous dirigez un hôtel resort 4 étoiles en zone côtière. Un ouragan de catégorie 2 est prévu dans 5 jours, pendant le week-end férié le plus important de l\'année. Vous avez 85% d\'occupation confirmée (210 chambres sur 250). Les compagnies aériennes émettent des alertes.\nContexte : L\'année dernière, un ouragan similaire a causé des dommages mineurs mais l\'hôtel a fermé 3 jours par précaution. Votre assurance a une franchise de 50 000 USD. Les revenus projetés sont de 180 000 USD.' }, rubric: { es: 'Evaluar: (1) Plan de contingencia para seguridad de huéspedes y personal, (2) Política de cancelación flexible vs. impacto financiero, (3) Comunicación proactiva con huéspedes, (4) Preparación física del hotel, (5) Coordinación con autoridades locales, (6) Plan de recuperación post-evento y estrategia para compensar pérdida de ingresos.', en: 'Evaluate: (1) Contingency plan for guest and staff safety, (2) Flexible cancellation policy vs. financial impact, (3) Proactive guest communication, (4) Physical hotel preparation, (5) Coordination with local authorities, (6) Post-event recovery plan and strategy to offset revenue loss.', fr: 'Évaluer : (1) Plan de contingence pour la sécurité, (2) Politique d\'annulation flexible vs. impact financier, (3) Communication proactive, (4) Préparation physique de l\'hôtel, (5) Coordination avec les autorités, (6) Plan de récupération post-événement.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  // Quality Standards — open-text
  { id: 'hosp-hgm-prof-6', profileId: 'hotel-general-manager', categoryId: 'hosp-hgm-professional', competencyId: 'hosp-hgm-quality-standards', type: 'open-text', content: { es: 'Su hotel acaba de recibir el resultado de la auditoría anual de la cadena/marca: el puntaje de satisfacción del huésped (GSS) ha bajado de 8.5 a 7.2 sobre 10 en el último año. Los principales comentarios negativos se concentran en: lentitud del check-in, limpieza inconsistente de habitaciones, y falta de variedad en el desayuno buffet. Describa su plan de acción integral para recuperar el puntaje a 8.5 en los próximos 6 meses.', en: 'Your hotel has just received the annual brand/chain audit result: the Guest Satisfaction Score (GSS) has dropped from 8.5 to 7.2 out of 10 over the past year. The main negative comments focus on: slow check-in, inconsistent room cleanliness, and lack of variety in the breakfast buffet. Describe your comprehensive action plan to recover the score to 8.5 within the next 6 months.', fr: 'Votre hôtel vient de recevoir les résultats de l\'audit annuel de la chaîne/marque : le score de satisfaction client (GSS) est passé de 8,5 à 7,2 sur 10 au cours de la dernière année. Les principaux commentaires négatifs portent sur : la lenteur du check-in, la propreté inconsistante des chambres et le manque de variété au buffet du petit-déjeuner. Décrivez votre plan d\'action intégral pour retrouver un score de 8,5 dans les 6 prochains mois.' }, rubric: { es: 'Evaluar: (1) Diagnóstico de causas raíz para cada área problemática, (2) Acciones específicas y medibles para check-in (tecnología, personal, procesos), (3) Plan de mejora para housekeeping (estándares, supervisión, capacitación), (4) Renovación de oferta de desayuno, (5) Sistema de monitoreo continuo de satisfacción, (6) Cronograma realista con hitos intermedios.', en: 'Evaluate: (1) Root cause diagnosis for each problem area, (2) Specific and measurable actions for check-in (technology, staffing, processes), (3) Improvement plan for housekeeping (standards, supervision, training), (4) Breakfast offering renovation, (5) Continuous satisfaction monitoring system, (6) Realistic timeline with intermediate milestones.', fr: 'Évaluer : (1) Diagnostic des causes profondes, (2) Actions spécifiques pour le check-in, (3) Plan d\'amélioration pour l\'entretien ménager, (4) Rénovation de l\'offre de petit-déjeuner, (5) Système de suivi continu de la satisfaction, (6) Calendrier réaliste avec jalons intermédiaires.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

