export const hospHgmSoftSkillsQuestions: Question[] = [
  // Leadership — multiple-choice
  { id: 'hosp-hgm-ss-1', profileId: 'hotel-general-manager', categoryId: 'hosp-hgm-soft-skills', competencyId: 'hosp-hgm-leadership', type: 'multiple-choice', content: { es: 'El jefe de housekeeping y el jefe de recepción tienen un conflicto recurrente: housekeeping se queja de que recepción hace check-ins antes de la hora sin verificar disponibilidad de habitaciones limpias, y recepción se queja de que housekeeping no actualiza el estatus de habitaciones en el sistema a tiempo. Esto genera quejas de huéspedes 2-3 veces por semana. ¿Cómo resuelve el conflicto?', en: 'The housekeeping manager and front desk manager have a recurring conflict: housekeeping complains that front desk does early check-ins without verifying clean room availability, and front desk complains that housekeeping does not update room status in the system on time. This generates guest complaints 2-3 times per week. How do you resolve the conflict?', fr: 'Le responsable de l\'entretien et le responsable de la réception ont un conflit récurrent : l\'entretien se plaint que la réception fait des check-ins anticipés sans vérifier la disponibilité, et la réception se plaint que l\'entretien ne met pas à jour le statut des chambres à temps. Cela génère des plaintes 2-3 fois par semaine. Comment résolvez-vous le conflit ?' }, options: [{ id: 'a', text: { es: 'Reunir a ambos jefes para rediseñar el proceso conjunto: establecer un protocolo de actualización de estatus en tiempo real en el PMS, definir ventanas de check-in temprano con autorización previa, crear un canal de comunicación directa entre ambos equipos y fijar una reunión operativa diaria breve', en: 'Bring both managers together to redesign the joint process: establish a real-time status update protocol in the PMS, define early check-in windows with prior authorization, create a direct communication channel between both teams, and set a brief daily operational meeting', fr: 'Réunir les deux responsables pour redessiner le processus conjoint : établir un protocole de mise à jour du statut en temps réel dans le PMS, définir des fenêtres de check-in anticipé avec autorisation préalable, créer un canal de communication directe et fixer une réunion opérationnelle quotidienne brève' }, value: 100 }, { id: 'b', text: { es: 'Establecer que recepción no puede hacer check-in hasta que housekeeping marque la habitación como lista en el sistema', en: 'Establish that front desk cannot check-in until housekeeping marks the room as ready in the system', fr: 'Établir que la réception ne peut pas faire de check-in tant que l\'entretien n\'a pas marqué la chambre comme prête dans le système' }, value: 50 }, { id: 'c', text: { es: 'Amonestar a ambos jefes por no resolver el problema entre ellos y exigir que lo solucionen', en: 'Reprimand both managers for not resolving the issue between themselves and demand they fix it', fr: 'Réprimander les deux responsables pour ne pas avoir résolu le problème entre eux et exiger qu\'ils le règlent' }, value: 15 }, { id: 'd', text: { es: 'Asignar a un supervisor de turno como intermediario para coordinar la comunicación entre ambos departamentos', en: 'Assign a shift supervisor as an intermediary to coordinate communication between both departments', fr: 'Affecter un superviseur de quart comme intermédiaire pour coordonner la communication entre les deux départements' }, value: 40 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  // Guest Relations — multiple-choice
  { id: 'hosp-hgm-ss-2', profileId: 'hotel-general-manager', categoryId: 'hosp-hgm-soft-skills', competencyId: 'hosp-hgm-guest-relations', type: 'multiple-choice', content: { es: 'Un huésped VIP (cliente corporativo que genera USD 200,000 anuales en reservas) publica una reseña negativa en TripAdvisor describiendo una mala experiencia: habitación no lista a su llegada, ruido de construcción no advertido y una facturación incorrecta. El tono es muy molesto y menciona que considerará otros hoteles. ¿Cuál es su respuesta?', en: 'A VIP guest (corporate client generating USD 200,000 annually in bookings) posts a negative TripAdvisor review describing a poor experience: room not ready on arrival, undisclosed construction noise, and incorrect billing. The tone is very upset and mentions considering other hotels. What is your response?', fr: 'Un client VIP (client corporatif générant 200 000 USD annuellement en réservations) publie un avis négatif sur TripAdvisor décrivant une mauvaise expérience : chambre pas prête à l\'arrivée, bruit de construction non signalé et facturation incorrecte. Le ton est très mécontent et mentionne envisager d\'autres hôtels. Quelle est votre réponse ?' }, options: [{ id: 'a', text: { es: 'Contactar personalmente al huésped por teléfono para disculparse, investigar internamente cada incidente, responder públicamente en TripAdvisor con profesionalismo, ofrecer una compensación significativa (crédito de estancia) e implementar mejoras para que no se repita, luego dar seguimiento personalizado', en: 'Personally contact the guest by phone to apologize, internally investigate each incident, respond publicly on TripAdvisor with professionalism, offer significant compensation (stay credit), implement improvements to prevent recurrence, then provide personalized follow-up', fr: 'Contacter personnellement le client par téléphone pour s\'excuser, enquêter en interne sur chaque incident, répondre publiquement sur TripAdvisor avec professionnalisme, offrir une compensation significative (crédit de séjour), mettre en œuvre des améliorations et assurer un suivi personnalisé' }, value: 100 }, { id: 'b', text: { es: 'Responder públicamente en TripAdvisor disculpándose y ofreciendo un descuento para su próxima visita', en: 'Respond publicly on TripAdvisor apologizing and offering a discount for the next visit', fr: 'Répondre publiquement sur TripAdvisor en s\'excusant et en offrant une réduction pour la prochaine visite' }, value: 45 }, { id: 'c', text: { es: 'Enviar un correo electrónico formal de disculpa con un voucher de cortesía', en: 'Send a formal apology email with a complimentary voucher', fr: 'Envoyer un courriel d\'excuses formel avec un bon de courtoisie' }, value: 35 }, { id: 'd', text: { es: 'Pedir al gerente de ventas corporativas que lo contacte para ofrecer una tarifa especial de retención', en: 'Ask the corporate sales manager to contact them to offer a special retention rate', fr: 'Demander au directeur des ventes corporatives de le contacter pour offrir un tarif spécial de rétention' }, value: 30 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  // Leadership — scale
  { id: 'hosp-hgm-ss-3', profileId: 'hotel-general-manager', categoryId: 'hosp-hgm-soft-skills', competencyId: 'hosp-hgm-leadership', type: 'scale', content: { es: '¿En qué medida se siente capaz de inspirar y motivar equipos diversos (recepción, cocina, mantenimiento, housekeeping) con diferentes niveles educativos y expectativas laborales?', en: 'To what extent do you feel capable of inspiring and motivating diverse teams (front desk, kitchen, maintenance, housekeeping) with different educational levels and work expectations?', fr: 'Dans quelle mesure vous sentez-vous capable d\'inspirer et de motiver des équipes diverses (réception, cuisine, maintenance, entretien) avec différents niveaux d\'éducation et attentes professionnelles ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Me resulta difícil conectar con equipos tan diversos', en: 'I find it difficult to connect with such diverse teams', fr: 'J\'ai du mal à me connecter avec des équipes aussi diverses' }, max: { es: 'Adapto naturalmente mi estilo de liderazgo a cada grupo y logro alto compromiso', en: 'I naturally adapt my leadership style to each group and achieve high engagement', fr: 'J\'adapte naturellement mon style de leadership à chaque groupe et obtiens un fort engagement' } }, maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  // Communication — scale
  { id: 'hosp-hgm-ss-4', profileId: 'hotel-general-manager', categoryId: 'hosp-hgm-soft-skills', competencyId: 'hosp-hgm-communication', type: 'scale', content: { es: '¿Qué tan cómodo se siente presentando resultados financieros y planes estratégicos a propietarios o inversionistas del hotel?', en: 'How comfortable do you feel presenting financial results and strategic plans to hotel owners or investors?', fr: 'À quel point vous sentez-vous à l\'aise pour présenter des résultats financiers et des plans stratégiques aux propriétaires ou investisseurs de l\'hôtel ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Poca experiencia en presentaciones a propietarios/inversionistas', en: 'Little experience in presentations to owners/investors', fr: 'Peu d\'expérience dans les présentations aux propriétaires/investisseurs' }, max: { es: 'Domino la comunicación ejecutiva con datos financieros y visión estratégica', en: 'I master executive communication with financial data and strategic vision', fr: 'Je maîtrise la communication exécutive avec données financières et vision stratégique' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  // Guest Relations — ranking
  { id: 'hosp-hgm-ss-5', profileId: 'hotel-general-manager', categoryId: 'hosp-hgm-soft-skills', competencyId: 'hosp-hgm-guest-relations', type: 'ranking', content: { es: 'Ordene las siguientes acciones por prioridad al recibir una queja formal de un huésped durante su estancia:', en: 'Rank the following actions by priority when receiving a formal guest complaint during their stay:', fr: 'Classez les actions suivantes par priorité lors de la réception d\'une plainte formelle d\'un client pendant son séjour :' }, options: [{ id: 'a', text: { es: 'Escuchar al huésped con empatía y sin interrumpir', en: 'Listen to the guest with empathy and without interrupting', fr: 'Écouter le client avec empathie et sans interrompre' }, value: 1 }, { id: 'b', text: { es: 'Ofrecer una solución concreta e inmediata', en: 'Offer a concrete and immediate solution', fr: 'Offrir une solution concrète et immédiate' }, value: 2 }, { id: 'c', text: { es: 'Hacer seguimiento para verificar satisfacción con la solución', en: 'Follow up to verify satisfaction with the solution', fr: 'Faire un suivi pour vérifier la satisfaction avec la solution' }, value: 3 }, { id: 'd', text: { es: 'Documentar el incidente y ajustar procesos para prevenir recurrencia', en: 'Document the incident and adjust processes to prevent recurrence', fr: 'Documenter l\'incident et ajuster les processus pour prévenir la récurrence' }, value: 4 }], maxScore: 100, aiEvaluated: false, order: 5, isActive: true },
  // Communication — open-text
  { id: 'hosp-hgm-ss-6', profileId: 'hotel-general-manager', categoryId: 'hosp-hgm-soft-skills', competencyId: 'hosp-hgm-communication', type: 'open-text', content: { es: 'El grupo propietario del hotel le informa que planean vender la propiedad a una cadena internacional que posiblemente cambiará la marca, los sistemas y potencialmente reestructurará el personal. La transacción se cerrará en 4 meses. Le piden mantener la confidencialidad pero usted sabe que los rumores ya circulan entre el personal, generando ansiedad y posibles renuncias de empleados clave. ¿Cómo maneja la comunicación interna y externa durante este período de transición?', en: 'The hotel ownership group informs you they plan to sell the property to an international chain that will likely rebrand, change systems, and potentially restructure staff. The transaction closes in 4 months. They ask you to maintain confidentiality but you know rumors are already circulating among staff, causing anxiety and potential resignations of key employees. How do you manage internal and external communication during this transition period?', fr: 'Le groupe propriétaire de l\'hôtel vous informe qu\'il prévoit de vendre la propriété à une chaîne internationale qui changera probablement la marque, les systèmes et restructurera potentiellement le personnel. La transaction se clôture dans 4 mois. On vous demande de maintenir la confidentialité mais vous savez que les rumeurs circulent déjà, causant de l\'anxiété et des démissions potentielles. Comment gérez-vous la communication interne et externe pendant cette période de transition ?' }, rubric: { es: 'Evaluar: (1) Equilibrio entre confidencialidad contractual y transparencia con el equipo, (2) Estrategia de retención de talento clave, (3) Manejo de rumores sin violar acuerdos de confidencialidad, (4) Preparación del equipo para la transición, (5) Comunicación con huéspedes y socios comerciales, (6) Protección de la operación y calidad del servicio durante la incertidumbre.', en: 'Evaluate: (1) Balance between contractual confidentiality and team transparency, (2) Key talent retention strategy, (3) Rumor management without violating confidentiality agreements, (4) Team preparation for transition, (5) Communication with guests and business partners, (6) Protection of operations and service quality during uncertainty.', fr: 'Évaluer : (1) Équilibre entre confidentialité et transparence, (2) Stratégie de rétention des talents clés, (3) Gestion des rumeurs, (4) Préparation de l\'équipe à la transition, (5) Communication avec les clients et partenaires, (6) Protection des opérations pendant l\'incertitude.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

