export const hospHgmReadinessQuestions: Question[] = [
  // Digital Transformation — multiple-choice
  { id: 'hosp-hgm-rd-1', profileId: 'hotel-general-manager', categoryId: 'hosp-hgm-readiness', competencyId: 'hosp-hgm-digital-transformation', type: 'multiple-choice', content: { es: 'Un proveedor tecnológico le presenta una solución de check-in/check-out completamente digital mediante app móvil, eliminando la necesidad de recepción física. La inversión es de USD 80,000 con un ahorro proyectado de USD 120,000 anuales en personal. Sin embargo, el 40% de sus huéspedes son mayores de 55 años y su marca se posiciona por el servicio personalizado. ¿Cuál es su enfoque?', en: 'A tech vendor presents a fully digital check-in/check-out solution via mobile app, eliminating the need for a physical front desk. The investment is USD 80,000 with projected annual savings of USD 120,000 in staffing. However, 40% of your guests are over 55 years old and your brand is positioned for personalized service. What is your approach?', fr: 'Un fournisseur technologique vous présente une solution de check-in/check-out entièrement numérique via application mobile. L\'investissement est de 80 000 USD avec des économies projetées de 120 000 USD par an. Cependant, 40% de vos clients ont plus de 55 ans et votre marque se positionne sur le service personnalisé. Quelle est votre approche ?' }, options: [{ id: 'a', text: { es: 'Implementar un modelo híbrido: ofrecer check-in digital como opción para quienes lo prefieran, mantener recepción con personal reducido pero altamente capacitado, reasignar parte del equipo a roles de concierge/experiencia del huésped, y medir adopción antes de expandir', en: 'Implement a hybrid model: offer digital check-in as an option for those who prefer it, maintain front desk with reduced but highly trained staff, reassign part of the team to concierge/guest experience roles, and measure adoption before expanding', fr: 'Mettre en œuvre un modèle hybride : offrir le check-in numérique en option, maintenir la réception avec un personnel réduit mais hautement qualifié, réaffecter une partie de l\'équipe à des rôles de conciergerie/expérience client, et mesurer l\'adoption avant d\'étendre' }, value: 100 }, { id: 'b', text: { es: 'Rechazar la propuesta porque contradice el posicionamiento de servicio personalizado de la marca', en: 'Reject the proposal because it contradicts the brand\'s personalized service positioning', fr: 'Rejeter la proposition car elle contredit le positionnement de service personnalisé de la marque' }, value: 30 }, { id: 'c', text: { es: 'Aceptar la implementación completa para maximizar los ahorros y modernizar el hotel', en: 'Accept full implementation to maximize savings and modernize the hotel', fr: 'Accepter la mise en œuvre complète pour maximiser les économies et moderniser l\'hôtel' }, value: 25 }, { id: 'd', text: { es: 'Posponer la decisión hasta que la tecnología esté más madura y la demografía de huéspedes cambie', en: 'Postpone the decision until the technology is more mature and guest demographics change', fr: 'Reporter la décision jusqu\'à ce que la technologie soit plus mature et que la démographie des clients change' }, value: 20 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  // Sustainability — multiple-choice
  { id: 'hosp-hgm-rd-2', profileId: 'hotel-general-manager', categoryId: 'hosp-hgm-readiness', competencyId: 'hosp-hgm-sustainability', type: 'multiple-choice', content: { es: 'Su cadena hotelera anuncia el objetivo de obtener la certificación Green Key para todas sus propiedades en 2 años. Esto implica inversiones significativas en eficiencia energética, gestión de residuos y reducción de consumo de agua. El presupuesto asignado a su hotel es de USD 150,000, pero su estimación preliminar indica que se necesitan al menos USD 250,000. ¿Cómo procede?', en: 'Your hotel chain announces the goal of obtaining Green Key certification for all properties within 2 years. This requires significant investments in energy efficiency, waste management, and water consumption reduction. The budget allocated to your hotel is USD 150,000, but your preliminary estimate indicates at least USD 250,000 is needed. How do you proceed?', fr: 'Votre chaîne hôtelière annonce l\'objectif d\'obtenir la certification Green Key pour toutes ses propriétés en 2 ans. Cela implique des investissements significatifs. Le budget alloué est de 150 000 USD mais votre estimation préliminaire indique qu\'au moins 250 000 USD sont nécessaires. Comment procédez-vous ?' }, options: [{ id: 'a', text: { es: 'Priorizar las iniciativas con mejor ROI y mayor impacto ambiental primero, presentar un business case a la cadena mostrando el ahorro operativo a 3 años de las inversiones adicionales, explorar incentivos fiscales verdes, y ejecutar las mejoras de bajo costo de inmediato (eliminación de plásticos, compostaje, capacitación)', en: 'Prioritize initiatives with the best ROI and highest environmental impact first, present a business case to the chain showing the 3-year operational savings of additional investments, explore green tax incentives, and execute low-cost improvements immediately (plastic elimination, composting, training)', fr: 'Prioriser les initiatives avec le meilleur ROI et le plus grand impact environnemental, présenter un business case à la chaîne montrant les économies opérationnelles sur 3 ans, explorer les incitations fiscales vertes, et exécuter les améliorations à faible coût immédiatement' }, value: 100 }, { id: 'b', text: { es: 'Informar a la cadena que el presupuesto es insuficiente y solicitar los fondos completos', en: 'Inform the chain that the budget is insufficient and request the full funds', fr: 'Informer la chaîne que le budget est insuffisant et demander les fonds complets' }, value: 35 }, { id: 'c', text: { es: 'Ejecutar solo las mejoras que entren en el presupuesto de USD 150,000 y buscar la certificación parcial', en: 'Execute only the improvements that fit within the USD 150,000 budget and seek partial certification', fr: 'Exécuter uniquement les améliorations qui entrent dans le budget de 150 000 USD et viser une certification partielle' }, value: 45 }, { id: 'd', text: { es: 'Retrasar el inicio hasta que se resuelva la brecha presupuestaria', en: 'Delay the start until the budget gap is resolved', fr: 'Retarder le début jusqu\'à ce que l\'écart budgétaire soit résolu' }, value: 15 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  // Digital Transformation — scale
  { id: 'hosp-hgm-rd-3', profileId: 'hotel-general-manager', categoryId: 'hosp-hgm-readiness', competencyId: 'hosp-hgm-digital-transformation', type: 'scale', content: { es: '¿Qué tan preparado se siente para evaluar e implementar soluciones de inteligencia artificial aplicadas a la hotelería (chatbots, pricing predictivo, personalización de experiencia)?', en: 'How prepared do you feel to evaluate and implement artificial intelligence solutions applied to hospitality (chatbots, predictive pricing, experience personalization)?', fr: 'À quel point vous sentez-vous préparé pour évaluer et mettre en œuvre des solutions d\'intelligence artificielle appliquées à l\'hôtellerie (chatbots, tarification prédictive, personnalisation de l\'expérience) ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Conozco poco sobre IA aplicada a hotelería', en: 'I know little about AI applied to hospitality', fr: 'Je connais peu l\'IA appliquée à l\'hôtellerie' }, max: { es: 'Tengo experiencia evaluando y liderando proyectos de IA en hoteles', en: 'I have experience evaluating and leading AI projects in hotels', fr: 'J\'ai de l\'expérience dans l\'évaluation et la direction de projets d\'IA dans les hôtels' } }, maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  // New Traveler — scale
  { id: 'hosp-hgm-rd-4', profileId: 'hotel-general-manager', categoryId: 'hosp-hgm-readiness', competencyId: 'hosp-hgm-new-traveler', type: 'scale', content: { es: '¿En qué medida ha adaptado la oferta de su hotel para atender las tendencias del viajero moderno (bleisure, nómadas digitales, experiencias locales, bienestar)?', en: 'To what extent have you adapted your hotel\'s offering to cater to modern traveler trends (bleisure, digital nomads, local experiences, wellness)?', fr: 'Dans quelle mesure avez-vous adapté l\'offre de votre hôtel pour répondre aux tendances du voyageur moderne (bleisure, nomades numériques, expériences locales, bien-être) ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Aún no he incorporado estas tendencias', en: 'I have not yet incorporated these trends', fr: 'Je n\'ai pas encore intégré ces tendances' }, max: { es: 'He liderado la transformación del hotel para atender al viajero moderno', en: 'I have led the hotel\'s transformation to serve the modern traveler', fr: 'J\'ai dirigé la transformation de l\'hôtel pour servir le voyageur moderne' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  // Sustainability — scenario
  { id: 'hosp-hgm-rd-5', profileId: 'hotel-general-manager', categoryId: 'hosp-hgm-readiness', competencyId: 'hosp-hgm-sustainability', type: 'scenario', content: { es: 'Un grupo de turistas europeos publica en redes sociales fotos de su hotel mostrando el uso de plásticos de un solo uso en el buffet (vasos, pajillas, envolturas), botellas plásticas de agua en las habitaciones y la falta de opciones de reciclaje visibles. El post se vuelve viral con más de 50,000 compartidos y varios medios locales retoman la historia. Algunos tour operadores europeos que representan el 20% de sus reservas le contactan preocupados.\nContexto: El cambio a alternativas sostenibles tiene un costo estimado de USD 45,000 anuales. Su margen operativo actual es del 18%.', en: 'A group of European tourists posts photos on social media showing your hotel\'s use of single-use plastics at the buffet (cups, straws, wrappers), plastic water bottles in rooms, and the lack of visible recycling options. The post goes viral with over 50,000 shares and several local media outlets pick up the story. Some European tour operators representing 20% of your bookings contact you with concerns.\nContext: Switching to sustainable alternatives has an estimated annual cost of USD 45,000. Your current operating margin is 18%.', fr: 'Un groupe de touristes européens publie sur les réseaux sociaux des photos montrant l\'utilisation de plastiques à usage unique dans votre hôtel. Le post devient viral avec plus de 50 000 partages. Certains tour-opérateurs européens représentant 20% de vos réservations vous contactent.\nContexte : Le passage aux alternatives durables a un coût estimé de 45 000 USD par an. Votre marge opérationnelle est de 18%.' }, rubric: { es: 'Evaluar: (1) Respuesta inmediata en redes sociales y medios, (2) Plan de acción acelerado para eliminar plásticos de un solo uso, (3) Comunicación transparente con tour operadores, (4) Estrategia de sostenibilidad integral más allá de los plásticos, (5) Análisis financiero del impacto vs. riesgo de pérdida de negocio, (6) Transformación de la crisis en oportunidad de posicionamiento.', en: 'Evaluate: (1) Immediate social media and media response, (2) Accelerated action plan to eliminate single-use plastics, (3) Transparent communication with tour operators, (4) Comprehensive sustainability strategy beyond plastics, (5) Financial analysis of impact vs. business loss risk, (6) Turning the crisis into a positioning opportunity.', fr: 'Évaluer : (1) Réponse immédiate sur les réseaux sociaux, (2) Plan d\'action accéléré pour éliminer les plastiques, (3) Communication transparente avec les tour-opérateurs, (4) Stratégie de durabilité intégrale, (5) Analyse financière, (6) Transformation de la crise en opportunité.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  // New Traveler — open-text
  { id: 'hosp-hgm-rd-6', profileId: 'hotel-general-manager', categoryId: 'hosp-hgm-readiness', competencyId: 'hosp-hgm-new-traveler', type: 'open-text', content: { es: 'Los datos de su hotel muestran que el segmento de "nómadas digitales" (estancias de 2-8 semanas, necesidad de WiFi de alta velocidad, espacios de coworking y flexibilidad de horarios) ha crecido un 300% en los últimos 2 años. Actualmente su hotel no tiene una oferta específica para este segmento. Describa su estrategia para capturar y fidelizar a los nómadas digitales sin alienar a su base actual de huéspedes de turismo tradicional y negocio corporativo.', en: 'Your hotel data shows that the "digital nomad" segment (2-8 week stays, need for high-speed WiFi, coworking spaces, and schedule flexibility) has grown 300% over the past 2 years. Currently your hotel has no specific offering for this segment. Describe your strategy to capture and retain digital nomads without alienating your current base of traditional tourism and corporate business guests.', fr: 'Les données de votre hôtel montrent que le segment des "nomades numériques" (séjours de 2-8 semaines, besoin de WiFi haut débit, espaces de coworking et flexibilité horaire) a augmenté de 300% en 2 ans. Actuellement, votre hôtel n\'a pas d\'offre spécifique pour ce segment. Décrivez votre stratégie pour capturer et fidéliser les nomades numériques sans aliéner votre base actuelle de tourisme traditionnel et clients corporatifs.' }, rubric: { es: 'Evaluar: (1) Análisis del segmento de nómadas digitales y sus necesidades específicas, (2) Diseño de producto (tarifas long-stay, paquetes, espacios de coworking), (3) Inversión en infraestructura (WiFi, enchufes, escritorios), (4) Estrategia de marketing dirigida (plataformas, comunidades), (5) Integración con la operación existente sin conflicto, (6) Métricas de éxito y modelo financiero.', en: 'Evaluate: (1) Analysis of digital nomad segment and specific needs, (2) Product design (long-stay rates, packages, coworking spaces), (3) Infrastructure investment (WiFi, outlets, desks), (4) Targeted marketing strategy (platforms, communities), (5) Integration with existing operations without conflict, (6) Success metrics and financial model.', fr: 'Évaluer : (1) Analyse du segment des nomades numériques, (2) Conception de produit (tarifs long séjour, espaces de coworking), (3) Investissement en infrastructure, (4) Stratégie marketing ciblée, (5) Intégration avec les opérations existantes, (6) Métriques de succès et modèle financier.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

// ============================================================================
// RESTAURANT MANAGER — PROFESSIONAL QUESTIONS
// ============================================================================

export const hospRmProfessionalQuestions: Question[] = [
  // F&B Operations — multiple-choice
  { id: 'hosp-rm-prof-1', profileId: 'restaurant-manager', categoryId: 'hosp-rm-professional', competencyId: 'hosp-rm-fb-operations', type: 'multiple-choice', content: { es: 'Es viernes por la noche y su restaurante de 120 cubiertos tiene lista de espera de 45 minutos. El sistema de reservas muestra 15 no-shows de los 80 reservados. Dos de sus seis meseros llamaron enfermos. La cocina reporta que se agotaron dos de los platillos estrella. ¿Cuál es su plan de acción inmediato?', en: 'It\'s Friday night and your 120-seat restaurant has a 45-minute wait list. The reservation system shows 15 no-shows out of 80 booked. Two of your six servers called in sick. The kitchen reports that two signature dishes are sold out. What is your immediate action plan?', fr: 'C\'est vendredi soir et votre restaurant de 120 couverts a une liste d\'attente de 45 minutes. Le système de réservation montre 15 absences sur 80 réservés. Deux de vos six serveurs sont absents pour maladie. La cuisine signale que deux plats phares sont épuisés. Quel est votre plan d\'action immédiat ?' }, options: [{ id: 'a', text: { es: 'Reorganizar el flujo: abrir las mesas de los no-shows para la lista de espera, redistribuir secciones entre los 4 meseros y asumir usted una sección, comunicar al equipo de cocina los platillos agotados para que sugieran alternativas, informar a los meseros para que redirijan los pedidos, y ajustar el ritmo de servicio para optimizar la rotación de mesas', en: 'Reorganize the flow: open no-show tables for the wait list, redistribute sections among the 4 servers and take a section yourself, communicate sold-out dishes to kitchen so they suggest alternatives, inform servers to redirect orders, and adjust service pace to optimize table turnover', fr: 'Réorganiser le flux : ouvrir les tables des absents pour la liste d\'attente, redistribuer les sections entre les 4 serveurs et prendre une section vous-même, communiquer les plats épuisés à la cuisine pour des alternatives, informer les serveurs et ajuster le rythme de service' }, value: 100 }, { id: 'b', text: { es: 'Cerrar la lista de espera y concentrarse en servir bien a los comensales actuales', en: 'Close the wait list and focus on serving current diners well', fr: 'Fermer la liste d\'attente et se concentrer sur le service des clients actuels' }, value: 40 }, { id: 'c', text: { es: 'Llamar a meseros de descanso para cubrir los turnos vacantes', en: 'Call off-duty servers to cover the vacant shifts', fr: 'Appeler les serveurs en repos pour couvrir les quarts vacants' }, value: 50 }, { id: 'd', text: { es: 'Reducir el menú a los platillos disponibles y simplificar la operación', en: 'Reduce the menu to available dishes and simplify operations', fr: 'Réduire le menu aux plats disponibles et simplifier les opérations' }, value: 35 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  // Cost Control — multiple-choice
  { id: 'hosp-rm-prof-2', profileId: 'restaurant-manager', categoryId: 'hosp-rm-professional', competencyId: 'hosp-rm-cost-control', type: 'multiple-choice', content: { es: 'Al revisar el informe mensual, detecta que el food cost subió del 28% al 35% sin cambios en el menú ni en los precios de venta. El inventario físico muestra discrepancias con el teórico en proteínas (-12%), lácteos (-8%) y frutas (-15%). Las ventas se han mantenido estables. ¿Cuál es su primera acción?', en: 'Reviewing the monthly report, you detect that food cost rose from 28% to 35% with no changes to the menu or selling prices. Physical inventory shows discrepancies with theoretical counts in proteins (-12%), dairy (-8%), and fruits (-15%). Sales have remained stable. What is your first action?', fr: 'En examinant le rapport mensuel, vous détectez que le food cost est passé de 28% à 35% sans changement de menu ni de prix. L\'inventaire physique montre des écarts avec le théorique en protéines (-12%), produits laitiers (-8%) et fruits (-15%). Les ventes sont stables. Quelle est votre première action ?' }, options: [{ id: 'a', text: { es: 'Investigar múltiples causas: auditar el proceso de recepción de mercancía, verificar porciones con fichas técnicas, revisar merma y desperdicio diario, evaluar posible robo/desvío con controles de acceso, cruzar compras con producción real, y establecer inventarios diarios temporales para las categorías problemáticas', en: 'Investigate multiple causes: audit goods receiving process, verify portions against spec sheets, review daily waste and spoilage, evaluate possible theft/diversion with access controls, cross-reference purchases with actual production, and establish temporary daily inventories for problem categories', fr: 'Enquêter sur les causes multiples : auditer la réception des marchandises, vérifier les portions avec les fiches techniques, examiner le gaspillage quotidien, évaluer le vol possible avec des contrôles d\'accès, croiser les achats avec la production réelle et établir des inventaires quotidiens temporaires' }, value: 100 }, { id: 'b', text: { es: 'Aumentar los precios del menú un 10% para compensar el aumento del food cost', en: 'Increase menu prices by 10% to offset the food cost increase', fr: 'Augmenter les prix du menu de 10% pour compenser l\'augmentation du food cost' }, value: 20 }, { id: 'c', text: { es: 'Cambiar de proveedores para buscar mejores precios en las categorías afectadas', en: 'Switch suppliers to find better prices in the affected categories', fr: 'Changer de fournisseurs pour trouver de meilleurs prix dans les catégories affectées' }, value: 30 }, { id: 'd', text: { es: 'Instalar cámaras en la cocina y el almacén para detectar posible robo', en: 'Install cameras in the kitchen and storage to detect possible theft', fr: 'Installer des caméras dans la cuisine et le stockage pour détecter un éventuel vol' }, value: 35 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  // Health & Safety — multiple-choice
  { id: 'hosp-rm-prof-3', profileId: 'restaurant-manager', categoryId: 'hosp-rm-professional', competencyId: 'hosp-rm-health-safety', type: 'multiple-choice', content: { es: 'Un cliente informa a su mesero que tuvo una reacción alérgica leve (urticaria) después de consumir un platillo que pidió "sin mariscos". Al investigar, descubre que la salsa del platillo contiene extracto de camarón y la ficha técnica no lo detallaba como alérgeno. El cliente no requiere hospitalización pero está molesto. ¿Cómo procede?', en: 'A customer informs your server they had a mild allergic reaction (hives) after consuming a dish they ordered "without shellfish." Upon investigation, you discover the dish\'s sauce contains shrimp extract and the spec sheet did not detail it as an allergen. The customer does not require hospitalization but is upset. How do you proceed?', fr: 'Un client informe votre serveur qu\'il a eu une réaction allergique légère (urticaire) après avoir consommé un plat commandé "sans fruits de mer." En enquêtant, vous découvrez que la sauce contient de l\'extrait de crevette et la fiche technique ne le détaillait pas comme allergène. Le client ne nécessite pas d\'hospitalisation mais est mécontent. Comment procédez-vous ?' }, options: [{ id: 'a', text: { es: 'Atender al cliente inmediatamente ofreciendo asistencia médica, disculparse personalmente, retirar el platillo del servicio hasta corregir la ficha técnica, auditar todas las fichas técnicas del menú para alérgenos, reentrenar al equipo en protocolos de alérgenos, documentar el incidente y cubrir cualquier gasto médico del cliente', en: 'Attend to the customer immediately offering medical assistance, apologize personally, remove the dish from service until the spec sheet is corrected, audit all menu spec sheets for allergens, retrain the team on allergen protocols, document the incident and cover any customer medical expenses', fr: 'Prendre en charge le client immédiatement en offrant une assistance médicale, s\'excuser personnellement, retirer le plat du service jusqu\'à correction de la fiche technique, auditer toutes les fiches techniques pour les allergènes, reformer l\'équipe sur les protocoles allergènes, documenter l\'incident et couvrir les frais médicaux' }, value: 100 }, { id: 'b', text: { es: 'Disculparse con el cliente, invitar la cena y corregir la ficha técnica del platillo', en: 'Apologize to the customer, comp the dinner, and correct the dish spec sheet', fr: 'S\'excuser auprès du client, offrir le dîner et corriger la fiche technique du plat' }, value: 45 }, { id: 'c', text: { es: 'Responsabilizar al chef por no incluir el alérgeno en la ficha técnica', en: 'Hold the chef responsible for not including the allergen in the spec sheet', fr: 'Tenir le chef responsable de ne pas avoir inclus l\'allergène dans la fiche technique' }, value: 20 }, { id: 'd', text: { es: 'Ofrecer disculpas y explicar que el restaurante no puede garantizar la ausencia total de alérgenos', en: 'Offer apologies and explain that the restaurant cannot guarantee the total absence of allergens', fr: 'Présenter des excuses et expliquer que le restaurant ne peut pas garantir l\'absence totale d\'allergènes' }, value: 15 }], maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  // F&B Operations — scale
  { id: 'hosp-rm-prof-4', profileId: 'restaurant-manager', categoryId: 'hosp-rm-professional', competencyId: 'hosp-rm-fb-operations', type: 'scale', content: { es: '¿Qué nivel de experiencia tiene gestionando la operación completa de un restaurante con más de 80 cubiertos y servicio de alimentos y bebidas?', en: 'What level of experience do you have managing the complete operation of a restaurant with over 80 seats and food and beverage service?', fr: 'Quel niveau d\'expérience avez-vous dans la gestion complète d\'un restaurant de plus de 80 couverts avec service de restauration ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Experiencia limitada en operación de restaurante', en: 'Limited restaurant operation experience', fr: 'Expérience limitée en exploitation de restaurant' }, max: { es: 'Amplia experiencia gestionando restaurantes de alto volumen', en: 'Extensive experience managing high-volume restaurants', fr: 'Vaste expérience dans la gestion de restaurants à fort volume' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  // Cost Control — scenario
  { id: 'hosp-rm-prof-5', profileId: 'restaurant-manager', categoryId: 'hosp-rm-professional', competencyId: 'hosp-rm-cost-control', type: 'scenario', content: { es: 'Usted administra un restaurante con ventas mensuales de USD 120,000. El propietario le informa que los costos de materia prima de sus principales proveedores aumentarán un 18% a partir del próximo mes debido a inflación y problemas de cadena de suministro. Su food cost actual es del 30% y el margen neto del 12%. Si absorbe el aumento completo, su margen cae al 6%. Los competidores directos aún no han subido precios.\nContexto: Su clientela es 60% recurrente. La encuesta de satisfacción más reciente muestra un puntaje de 4.5/5. El contrato con el local se renueva en 8 meses.', en: 'You manage a restaurant with monthly sales of USD 120,000. The owner informs you that raw material costs from your main suppliers will increase 18% starting next month due to inflation and supply chain issues. Your current food cost is 30% and net margin is 12%. If you absorb the full increase, your margin drops to 6%. Direct competitors have not yet raised prices.\nContext: Your clientele is 60% recurring. The latest satisfaction survey shows a 4.5/5 score. Your lease renews in 8 months.', fr: 'Vous gérez un restaurant avec des ventes mensuelles de 120 000 USD. Le propriétaire vous informe que les coûts des matières premières augmenteront de 18% le mois prochain. Votre food cost actuel est de 30% et la marge nette de 12%. Si vous absorbez l\'augmentation, votre marge tombe à 6%.\nContexte : 60% de clientèle récurrente. Score de satisfaction de 4,5/5. Bail à renouveler dans 8 mois.' }, rubric: { es: 'Evaluar: (1) Estrategia de ingeniería de menú (rediseño con productos alternativos, ajuste de porciones, nuevos platillos con mejor margen), (2) Negociación con proveedores (volumen, plazos, proveedores alternativos), (3) Ajuste estratégico de precios (selectivo, no generalizado), (4) Reducción de merma y desperdicio, (5) Comunicación de valor al cliente si hay ajustes de precio, (6) Proyección financiera a 6 meses con diferentes escenarios.', en: 'Evaluate: (1) Menu engineering strategy (redesign with alternative products, portion adjustment, new higher-margin dishes), (2) Supplier negotiation (volume, terms, alternative suppliers), (3) Strategic price adjustment (selective, not across-the-board), (4) Waste and spoilage reduction, (5) Value communication to customers if prices adjust, (6) 6-month financial projection with different scenarios.', fr: 'Évaluer : (1) Stratégie d\'ingénierie de menu, (2) Négociation avec les fournisseurs, (3) Ajustement stratégique des prix, (4) Réduction du gaspillage, (5) Communication de valeur aux clients, (6) Projection financière sur 6 mois.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  // Health & Safety — open-text
  { id: 'hosp-rm-prof-6', profileId: 'restaurant-manager', categoryId: 'hosp-rm-professional', competencyId: 'hosp-rm-health-safety', type: 'open-text', content: { es: 'La autoridad sanitaria realizará una inspección programada de su restaurante en 2 semanas. La última inspección hace 6 meses resultó en 3 observaciones menores. Describa su plan completo de preparación para la inspección, incluyendo las áreas que revisará, las acciones preventivas y cómo involucra a todo el equipo.', en: 'The health authority will conduct a scheduled inspection of your restaurant in 2 weeks. The last inspection 6 months ago resulted in 3 minor observations. Describe your complete preparation plan for the inspection, including the areas you will review, preventive actions, and how you involve the entire team.', fr: 'L\'autorité sanitaire effectuera une inspection programmée de votre restaurant dans 2 semaines. La dernière inspection il y a 6 mois a résulté en 3 observations mineures. Décrivez votre plan complet de préparation pour l\'inspection, incluant les domaines à examiner, les actions préventives et la manière dont vous impliquez toute l\'équipe.' }, rubric: { es: 'Evaluar: (1) Revisión sistemática de todos los puntos de la última inspección, (2) Plan de limpieza profunda por áreas, (3) Verificación de documentación (registros de temperatura, fichas técnicas, certificados de fumigación, análisis de agua), (4) Capacitación de refuerzo al personal en BPM y HACCP, (5) Simulacro de inspección interno, (6) Lista de verificación con responsables y fechas.', en: 'Evaluate: (1) Systematic review of all points from last inspection, (2) Deep cleaning plan by area, (3) Documentation verification (temperature logs, spec sheets, pest control certificates, water analysis), (4) Staff refresher training on GMP and HACCP, (5) Internal mock inspection, (6) Checklist with responsible parties and dates.', fr: 'Évaluer : (1) Révision systématique des points de la dernière inspection, (2) Plan de nettoyage en profondeur, (3) Vérification de la documentation, (4) Formation de rappel du personnel, (5) Simulation d\'inspection interne, (6) Liste de vérification avec responsables et dates.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

// ============================================================================
// RESTAURANT MANAGER — SOFT SKILLS QUESTIONS
