export const hospRmSoftSkillsQuestions: Question[] = [
  // Team Management — multiple-choice
  { id: 'hosp-rm-ss-1', profileId: 'restaurant-manager', categoryId: 'hosp-rm-soft-skills', competencyId: 'hosp-rm-team-management', type: 'multiple-choice', content: { es: 'Su restaurante tiene una rotación de personal del 45% anual. Los exit interviews revelan tres causas principales: salarios percibidos como bajos (aunque están en el promedio del mercado), horarios impredecibles y falta de oportunidades de crecimiento. ¿Cuál es su estrategia de retención?', en: 'Your restaurant has 45% annual staff turnover. Exit interviews reveal three main causes: salaries perceived as low (though they are at market average), unpredictable schedules, and lack of growth opportunities. What is your retention strategy?', fr: 'Votre restaurant a une rotation du personnel de 45% par an. Les entretiens de départ révèlent trois causes : salaires perçus comme bas (bien qu\'au marché), horaires imprévisibles et manque d\'opportunités de croissance. Quelle est votre stratégie de rétention ?' }, options: [{ id: 'a', text: { es: 'Implementar un programa integral: crear plan de carrera con niveles (mesero Jr., Sr., capitán), publicar horarios con 2 semanas de anticipación, establecer un sistema de propinas transparente y bonos por desempeño, ofrecer capacitación certificada en servicio y vinos, y realizar encuestas mensuales de clima laboral', en: 'Implement a comprehensive program: create a career path with levels (Jr. server, Sr. server, captain), publish schedules 2 weeks in advance, establish a transparent tip system and performance bonuses, offer certified training in service and wines, and conduct monthly workplace climate surveys', fr: 'Mettre en œuvre un programme intégral : créer un plan de carrière avec niveaux, publier les horaires 2 semaines à l\'avance, établir un système de pourboires transparent et des primes de performance, offrir une formation certifiée en service et vins, et réaliser des enquêtes mensuelles de climat de travail' }, value: 100 }, { id: 'b', text: { es: 'Aumentar los salarios un 10% por encima del mercado', en: 'Increase salaries 10% above market', fr: 'Augmenter les salaires de 10% au-dessus du marché' }, value: 40 }, { id: 'c', text: { es: 'Mejorar los horarios implementando turnos fijos y rotativos predecibles', en: 'Improve schedules by implementing fixed and predictable rotating shifts', fr: 'Améliorer les horaires en mettant en place des quarts fixes et rotatifs prévisibles' }, value: 45 }, { id: 'd', text: { es: 'Aceptar que la alta rotación es normal en la industria y enfocarse en procesos de inducción más rápidos', en: 'Accept that high turnover is normal in the industry and focus on faster onboarding processes', fr: 'Accepter que la forte rotation est normale dans l\'industrie et se concentrer sur des processus d\'intégration plus rapides' }, value: 15 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  // Customer Experience — multiple-choice
  { id: 'hosp-rm-ss-2', profileId: 'restaurant-manager', categoryId: 'hosp-rm-soft-skills', competencyId: 'hosp-rm-customer-experience', type: 'multiple-choice', content: { es: 'Una pareja celebra su aniversario en su restaurante. El mesero derrama accidentalmente una copa de vino tinto sobre el vestido blanco de la clienta. La clienta está visiblemente molesta y su pareja exige hablar con el gerente. ¿Cuál es su respuesta inmediata?', en: 'A couple is celebrating their anniversary at your restaurant. The server accidentally spills a glass of red wine on the female guest\'s white dress. The guest is visibly upset and her partner demands to speak with the manager. What is your immediate response?', fr: 'Un couple célèbre son anniversaire dans votre restaurant. Le serveur renverse accidentellement un verre de vin rouge sur la robe blanche de la cliente. La cliente est visiblement contrariée et son partenaire demande à parler au gérant. Quelle est votre réponse immédiate ?' }, options: [{ id: 'a', text: { es: 'Acudir de inmediato, disculparse sinceramente, ofrecer productos de limpieza de emergencia, cubrir el costo de la tintorería profesional del vestido, invitar la cena completa, ofrecer una reserva de cortesía para repetir la celebración del aniversario, y dar seguimiento personal al día siguiente', en: 'Go immediately, sincerely apologize, offer emergency cleaning products, cover the cost of professional dry cleaning, comp the entire dinner, offer a complimentary reservation to redo the anniversary celebration, and personally follow up the next day', fr: 'Se rendre immédiatement, s\'excuser sincèrement, offrir des produits de nettoyage d\'urgence, couvrir le pressing professionnel, offrir le dîner complet, proposer une réservation de courtoisie pour refaire la célébration et faire un suivi personnel le lendemain' }, value: 100 }, { id: 'b', text: { es: 'Disculparse, invitar la cena y ofrecer cubrir el costo del vestido si no se puede limpiar', en: 'Apologize, comp the dinner, and offer to cover the dress cost if it cannot be cleaned', fr: 'S\'excuser, offrir le dîner et proposer de couvrir le coût de la robe si elle ne peut être nettoyée' }, value: 60 }, { id: 'c', text: { es: 'Disculparse, invitar las bebidas y enviar un postre de cortesía', en: 'Apologize, comp the beverages, and send a complimentary dessert', fr: 'S\'excuser, offrir les boissons et envoyer un dessert de courtoisie' }, value: 25 }, { id: 'd', text: { es: 'Pedir al mesero que se disculpe personalmente y ofrecer un descuento del 50% en la cuenta', en: 'Ask the server to personally apologize and offer a 50% discount on the bill', fr: 'Demander au serveur de s\'excuser personnellement et offrir une réduction de 50% sur l\'addition' }, value: 30 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  // Team Management — scale
  { id: 'hosp-rm-ss-3', profileId: 'restaurant-manager', categoryId: 'hosp-rm-soft-skills', competencyId: 'hosp-rm-team-management', type: 'scale', content: { es: '¿Qué tan efectivo se considera capacitando y desarrollando meseros nuevos sin experiencia previa en restaurantes?', en: 'How effective do you consider yourself at training and developing new servers with no prior restaurant experience?', fr: 'À quel point vous considérez-vous efficace pour former et développer de nouveaux serveurs sans expérience préalable en restauration ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Prefiero contratar personal con experiencia previa', en: 'I prefer hiring staff with prior experience', fr: 'Je préfère embaucher du personnel avec de l\'expérience' }, max: { es: 'Tengo un sistema probado de capacitación que transforma novatos en meseros competentes en pocas semanas', en: 'I have a proven training system that transforms beginners into competent servers in a few weeks', fr: 'J\'ai un système de formation éprouvé qui transforme les débutants en serveurs compétents en quelques semaines' } }, maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  // Pressure Management — scale
  { id: 'hosp-rm-ss-4', profileId: 'restaurant-manager', categoryId: 'hosp-rm-soft-skills', competencyId: 'hosp-rm-pressure-management', type: 'scale', content: { es: '¿Cómo califica su capacidad para mantener la calma, tomar decisiones rápidas y coordinar al equipo durante un servicio de alta demanda con imprevistos?', en: 'How do you rate your ability to stay calm, make quick decisions, and coordinate the team during a high-demand service with unexpected issues?', fr: 'Comment évaluez-vous votre capacité à rester calme, prendre des décisions rapides et coordonner l\'équipe lors d\'un service à forte demande avec des imprévus ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Los servicios de alta presión me generan estrés significativo', en: 'High-pressure services cause me significant stress', fr: 'Les services à haute pression me causent un stress important' }, max: { es: 'Me desenvuelvo con confianza y claridad incluso en los servicios más caóticos', en: 'I perform with confidence and clarity even during the most chaotic services', fr: 'Je m\'en sors avec confiance et clarté même lors des services les plus chaotiques' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  // Customer Experience — ranking
  { id: 'hosp-rm-ss-5', profileId: 'restaurant-manager', categoryId: 'hosp-rm-soft-skills', competencyId: 'hosp-rm-customer-experience', type: 'ranking', content: { es: 'Ordene los siguientes factores por su importancia para lograr que un cliente regrese a su restaurante:', en: 'Rank the following factors by their importance in getting a customer to return to your restaurant:', fr: 'Classez les facteurs suivants par leur importance pour fidéliser un client dans votre restaurant :' }, options: [{ id: 'a', text: { es: 'Calidad y consistencia de la comida', en: 'Food quality and consistency', fr: 'Qualité et constance de la nourriture' }, value: 1 }, { id: 'b', text: { es: 'Calidad del servicio y atención personalizada', en: 'Service quality and personalized attention', fr: 'Qualité du service et attention personnalisée' }, value: 2 }, { id: 'c', text: { es: 'Ambiente y atmósfera del restaurante', en: 'Restaurant ambiance and atmosphere', fr: 'Ambiance et atmosphère du restaurant' }, value: 3 }, { id: 'd', text: { es: 'Relación calidad-precio percibida', en: 'Perceived value for money', fr: 'Rapport qualité-prix perçu' }, value: 4 }], maxScore: 100, aiEvaluated: false, order: 5, isActive: true },
  // Pressure Management — open-text
  { id: 'hosp-rm-ss-6', profileId: 'restaurant-manager', categoryId: 'hosp-rm-soft-skills', competencyId: 'hosp-rm-pressure-management', type: 'open-text', content: { es: 'Describa la situación más desafiante que haya enfrentado durante un servicio de restaurante (o, si no tiene experiencia, imagine un escenario donde todo sale mal simultáneamente: retrasos en cocina, quejas múltiples, personal insuficiente y un corte de luz). ¿Cómo lo manejó o lo manejaría? ¿Qué aprendizaje obtuvo o obtendría?', en: 'Describe the most challenging situation you have faced during a restaurant service (or, if you have no experience, imagine a scenario where everything goes wrong simultaneously: kitchen delays, multiple complaints, insufficient staff, and a power outage). How did you handle it or how would you handle it? What lessons did you learn or would you learn?', fr: 'Décrivez la situation la plus difficile que vous avez rencontrée pendant un service de restaurant (ou, si vous n\'avez pas d\'expérience, imaginez un scénario où tout va mal simultanément : retards en cuisine, plaintes multiples, personnel insuffisant et coupure de courant). Comment l\'avez-vous géré ou le géreriez-vous ? Quels enseignements en avez-vous tirés ?' }, rubric: { es: 'Evaluar: (1) Capacidad de mantener la calma y priorizar, (2) Toma de decisiones rápida y pragmática, (3) Comunicación clara con el equipo bajo presión, (4) Enfoque en la experiencia del cliente a pesar del caos, (5) Liderazgo visible y ejemplo personal, (6) Reflexión y aprendizaje post-evento.', en: 'Evaluate: (1) Ability to stay calm and prioritize, (2) Quick and pragmatic decision-making, (3) Clear communication with the team under pressure, (4) Focus on customer experience despite chaos, (5) Visible leadership and personal example, (6) Post-event reflection and learning.', fr: 'Évaluer : (1) Capacité à rester calme et à prioriser, (2) Prise de décision rapide et pragmatique, (3) Communication claire sous pression, (4) Focus sur l\'expérience client malgré le chaos, (5) Leadership visible, (6) Réflexion et apprentissage post-événement.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

// ============================================================================
// RESTAURANT MANAGER — READINESS QUESTIONS
// ============================================================================

export const hospRmReadinessQuestions: Question[] = [
  // Digital Delivery — multiple-choice
  { id: 'hosp-rm-rd-1', profileId: 'restaurant-manager', categoryId: 'hosp-rm-readiness', competencyId: 'hosp-rm-digital-delivery', type: 'multiple-choice', content: { es: 'Las plataformas de delivery (Uber Eats, Rappi, DoorDash) representan el 25% de sus ventas pero con comisiones del 30%. El margen neto del delivery es solo del 3% vs. 15% en salón. Sin embargo, las ventas de delivery crecen un 20% anual mientras el salón se mantiene estable. ¿Cuál es su estrategia de canal digital?', en: 'Delivery platforms (Uber Eats, Rappi, DoorDash) represent 25% of your sales but with 30% commissions. The net margin on delivery is only 3% vs. 15% in-house. However, delivery sales grow 20% annually while dine-in remains stable. What is your digital channel strategy?', fr: 'Les plateformes de livraison (Uber Eats, Rappi, DoorDash) représentent 25% de vos ventes mais avec des commissions de 30%. La marge nette sur la livraison est de seulement 3% vs. 15% en salle. Cependant, les ventes de livraison augmentent de 20% par an. Quelle est votre stratégie de canal numérique ?' }, options: [{ id: 'a', text: { es: 'Desarrollar una estrategia multicanal: mantener presencia en plataformas para visibilidad, crear un sistema de pedidos directos propio (web/WhatsApp) con incentivos para reducir dependencia, diseñar un menú optimizado para delivery con márgenes superiores, y negociar comisiones reducidas por volumen', en: 'Develop a multichannel strategy: maintain platform presence for visibility, create an own direct ordering system (web/WhatsApp) with incentives to reduce dependence, design a delivery-optimized menu with higher margins, and negotiate reduced commissions by volume', fr: 'Développer une stratégie multicanal : maintenir la présence sur les plateformes pour la visibilité, créer un système de commande directe propre avec des incitations, concevoir un menu optimisé pour la livraison avec de meilleures marges, et négocier des commissions réduites par volume' }, value: 100 }, { id: 'b', text: { es: 'Salir de las plataformas de delivery y enfocarse en el negocio en salón', en: 'Exit delivery platforms and focus on the dine-in business', fr: 'Quitter les plateformes de livraison et se concentrer sur le service en salle' }, value: 20 }, { id: 'c', text: { es: 'Aumentar los precios del menú de delivery un 15% para compensar las comisiones', en: 'Increase delivery menu prices by 15% to offset commissions', fr: 'Augmenter les prix du menu de livraison de 15% pour compenser les commissions' }, value: 40 }, { id: 'd', text: { es: 'Aceptar el margen bajo del delivery como costo de adquisición de nuevos clientes', en: 'Accept the low delivery margin as a customer acquisition cost', fr: 'Accepter la faible marge de la livraison comme coût d\'acquisition de nouveaux clients' }, value: 35 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  // Gastronomic Trends — multiple-choice
  { id: 'hosp-rm-rd-2', profileId: 'restaurant-manager', categoryId: 'hosp-rm-readiness', competencyId: 'hosp-rm-gastronomic-trends', type: 'multiple-choice', content: { es: 'Los datos de ventas muestran que las opciones vegetarianas y veganas de su menú (actualmente 2 de 24 platillos) representan el 18% de los pedidos y crecen un 30% anual. Varios clientes han comentado en reseñas que "les gustaría más opciones plant-based". Su chef es escéptico y opina que "la cocina tradicional es la esencia del restaurante". ¿Cómo aborda la situación?', en: 'Sales data shows that vegetarian and vegan options on your menu (currently 2 of 24 dishes) represent 18% of orders and are growing 30% annually. Several customers have commented in reviews that they "would like more plant-based options." Your chef is skeptical and believes "traditional cuisine is the restaurant\'s essence." How do you approach the situation?', fr: 'Les données de vente montrent que les options végétariennes et véganes de votre menu (actuellement 2 sur 24 plats) représentent 18% des commandes et augmentent de 30% par an. Votre chef est sceptique et pense que "la cuisine traditionnelle est l\'essence du restaurant." Comment abordez-vous la situation ?' }, options: [{ id: 'a', text: { es: 'Presentar los datos al chef y co-crear una estrategia: ampliar a 5-6 opciones plant-based sin eliminar platillos tradicionales populares, posicionar las nuevas opciones como innovación culinaria (no como sustituto), hacer un periodo de prueba de 3 meses con menú especial y medir resultados', en: 'Present the data to the chef and co-create a strategy: expand to 5-6 plant-based options without eliminating popular traditional dishes, position new options as culinary innovation (not substitutes), run a 3-month trial period with a special menu and measure results', fr: 'Présenter les données au chef et co-créer une stratégie : étendre à 5-6 options végétales sans éliminer les plats traditionnels populaires, positionner les nouvelles options comme innovation culinaire, faire une période d\'essai de 3 mois et mesurer les résultats' }, value: 100 }, { id: 'b', text: { es: 'Respetar la visión del chef y mantener el menú actual con las 2 opciones vegetarianas', en: 'Respect the chef\'s vision and keep the current menu with the 2 vegetarian options', fr: 'Respecter la vision du chef et maintenir le menu actuel avec les 2 options végétariennes' }, value: 20 }, { id: 'c', text: { es: 'Ordenar al chef que agregue 6 opciones veganas al menú para satisfacer la demanda', en: 'Order the chef to add 6 vegan options to the menu to meet demand', fr: 'Ordonner au chef d\'ajouter 6 options véganes au menu pour satisfaire la demande' }, value: 25 }, { id: 'd', text: { es: 'Crear un menú vegano separado disponible solo bajo pedido', en: 'Create a separate vegan menu available only on request', fr: 'Créer un menu végan séparé disponible uniquement sur demande' }, value: 35 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  // Digital Delivery — scale
  { id: 'hosp-rm-rd-3', profileId: 'restaurant-manager', categoryId: 'hosp-rm-readiness', competencyId: 'hosp-rm-digital-delivery', type: 'scale', content: { es: '¿Qué tan cómodo se siente gestionando la presencia digital del restaurante (redes sociales, plataformas de reseñas, marketing digital, menús QR)?', en: 'How comfortable do you feel managing the restaurant\'s digital presence (social media, review platforms, digital marketing, QR menus)?', fr: 'À quel point vous sentez-vous à l\'aise pour gérer la présence numérique du restaurant (réseaux sociaux, plateformes d\'avis, marketing digital, menus QR) ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Tengo poca experiencia en marketing y gestión digital', en: 'I have little experience in digital marketing and management', fr: 'J\'ai peu d\'expérience en marketing et gestion numérique' }, max: { es: 'Domino las herramientas digitales y las uso activamente para impulsar el negocio', en: 'I master digital tools and actively use them to drive the business', fr: 'Je maîtrise les outils numériques et les utilise activement pour développer l\'activité' } }, maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  // Food Sustainability — scale
  { id: 'hosp-rm-rd-4', profileId: 'restaurant-manager', categoryId: 'hosp-rm-readiness', competencyId: 'hosp-rm-food-sustainability', type: 'scale', content: { es: '¿En qué medida ha implementado prácticas de sostenibilidad alimentaria en restaurantes bajo su gestión (reducción de desperdicio, compostaje, proveedores locales, empaques ecológicos)?', en: 'To what extent have you implemented food sustainability practices in restaurants under your management (waste reduction, composting, local sourcing, eco-friendly packaging)?', fr: 'Dans quelle mesure avez-vous mis en œuvre des pratiques de durabilité alimentaire dans les restaurants sous votre gestion (réduction du gaspillage, compostage, fournisseurs locaux, emballages écologiques) ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'No he implementado prácticas de sostenibilidad específicas', en: 'I have not implemented specific sustainability practices', fr: 'Je n\'ai pas mis en œuvre de pratiques de durabilité spécifiques' }, max: { es: 'He liderado programas de sostenibilidad exitosos con resultados medibles', en: 'I have led successful sustainability programs with measurable results', fr: 'J\'ai dirigé des programmes de durabilité réussis avec des résultats mesurables' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  // Gastronomic Trends — scenario
  { id: 'hosp-rm-rd-5', profileId: 'restaurant-manager', categoryId: 'hosp-rm-readiness', competencyId: 'hosp-rm-gastronomic-trends', type: 'scenario', content: { es: 'Un influencer gastronómico con 500,000 seguidores le propone una colaboración: creará contenido sobre su restaurante a cambio de 4 cenas gratuitas para grupos de 6 personas y USD 2,000 de honorarios. La inversión total sería de aproximadamente USD 4,500. Su presupuesto de marketing mensual es de USD 3,000 y ya está comprometido. Sin embargo, tres restaurantes competidores recientemente obtuvieron aumentos de reservas del 40% tras colaboraciones con influencers similares.\nContexto: Su restaurante tiene 3.8 estrellas en Google con 450 reseñas. La competencia directa tiene 4.5 estrellas con 1,200 reseñas.', en: 'A food influencer with 500,000 followers proposes a collaboration: they will create content about your restaurant in exchange for 4 complimentary dinners for groups of 6 and USD 2,000 in fees. Total investment would be approximately USD 4,500. Your monthly marketing budget is USD 3,000 and already committed. However, three competing restaurants recently achieved 40% booking increases after similar influencer collaborations.\nContext: Your restaurant has 3.8 stars on Google with 450 reviews. Direct competition has 4.5 stars with 1,200 reviews.', fr: 'Un influenceur gastronomique avec 500 000 abonnés vous propose une collaboration : il créera du contenu sur votre restaurant en échange de 4 dîners gratuits pour des groupes de 6 personnes et 2 000 USD d\'honoraires. L\'investissement total serait d\'environ 4 500 USD. Votre budget marketing mensuel est de 3 000 USD et déjà engagé.\nContexte : Votre restaurant a 3,8 étoiles sur Google avec 450 avis. La concurrence directe a 4,5 étoiles avec 1 200 avis.' }, rubric: { es: 'Evaluar: (1) Análisis del ROI potencial de la colaboración, (2) Evaluación del perfil del influencer (audiencia, engagement, alineación con la marca), (3) Estrategia de financiamiento (reasignación de presupuesto, inversión adicional justificada), (4) Negociación de condiciones (contenido específico, exclusividad, métricas de desempeño), (5) Plan para capitalizar el contenido generado, (6) Estrategia complementaria para mejorar las reseñas de Google.', en: 'Evaluate: (1) Potential ROI analysis of the collaboration, (2) Influencer profile evaluation (audience, engagement, brand alignment), (3) Funding strategy (budget reallocation, justified additional investment), (4) Condition negotiation (specific content, exclusivity, performance metrics), (5) Plan to leverage generated content, (6) Complementary strategy to improve Google reviews.', fr: 'Évaluer : (1) Analyse du ROI potentiel, (2) Évaluation du profil de l\'influenceur, (3) Stratégie de financement, (4) Négociation des conditions, (5) Plan pour capitaliser le contenu généré, (6) Stratégie complémentaire pour améliorer les avis Google.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  // Food Sustainability — open-text
  { id: 'hosp-rm-rd-6', profileId: 'restaurant-manager', categoryId: 'hosp-rm-readiness', competencyId: 'hosp-rm-food-sustainability', type: 'open-text', content: { es: 'Su restaurante genera un promedio de 80 kg de desperdicio alimentario diario. El municipio acaba de aprobar una ordenanza que exige a los restaurantes reducir su desperdicio alimentario en un 50% en los próximos 18 meses o enfrentar multas significativas. Describa su plan integral para cumplir con esta meta, incluyendo cambios en compras, preparación, servicio y gestión de residuos.', en: 'Your restaurant generates an average of 80 kg of food waste daily. The municipality has just approved an ordinance requiring restaurants to reduce their food waste by 50% within the next 18 months or face significant fines. Describe your comprehensive plan to meet this goal, including changes in purchasing, preparation, service, and waste management.', fr: 'Votre restaurant génère en moyenne 80 kg de déchets alimentaires par jour. La municipalité vient d\'approuver une ordonnance exigeant que les restaurants réduisent leurs déchets alimentaires de 50% dans les 18 prochains mois. Décrivez votre plan intégral pour atteindre cet objectif, incluant les changements dans les achats, la préparation, le service et la gestion des déchets.' }, rubric: { es: 'Evaluar: (1) Auditoría de desperdicio por categoría (preparación, platos devueltos, buffet, vencimiento), (2) Ajuste de compras y porciones basado en datos, (3) Técnicas de aprovechamiento integral (caldos, salsas, menú del día), (4) Programa de compostaje o donación de alimentos, (5) Capacitación del equipo en reducción de merma, (6) Sistema de medición y seguimiento continuo.', en: 'Evaluate: (1) Waste audit by category (preparation, returned plates, buffet, expiration), (2) Data-based purchasing and portion adjustment, (3) Whole-ingredient utilization techniques (stocks, sauces, daily specials), (4) Composting or food donation program, (5) Team training in waste reduction, (6) Measurement and continuous monitoring system.', fr: 'Évaluer : (1) Audit des déchets par catégorie, (2) Ajustement des achats et portions, (3) Techniques d\'utilisation intégrale, (4) Programme de compostage ou de don alimentaire, (5) Formation de l\'équipe, (6) Système de mesure et suivi continu.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

// ============================================================================
// FRONT DESK AGENT — PROFESSIONAL QUESTIONS
// ============================================================================

export const hospFdaProfessionalQuestions: Question[] = [
  // Front Desk Operations — multiple-choice
  { id: 'hosp-fda-prof-1', profileId: 'front-desk-agent', categoryId: 'hosp-fda-professional', competencyId: 'hosp-fda-front-desk-ops', type: 'multiple-choice', content: { es: 'Un huésped llega al hotel a las 10:00 AM (5 horas antes del check-in estándar de las 3:00 PM) después de un vuelo largo y le pide su habitación inmediatamente. El hotel está al 90% de ocupación y housekeeping aún no ha comenzado el turno de limpieza. No hay habitaciones listas. ¿Cuál es su respuesta?', en: 'A guest arrives at the hotel at 10:00 AM (5 hours before the standard 3:00 PM check-in) after a long flight and requests their room immediately. The hotel is at 90% occupancy and housekeeping has not yet started the cleaning shift. No rooms are ready. What is your response?', fr: 'Un client arrive à l\'hôtel à 10h00 (5 heures avant le check-in standard de 15h00) après un long vol et demande sa chambre immédiatement. L\'hôtel est à 90% d\'occupation et le service d\'entretien n\'a pas encore commencé. Aucune chambre n\'est prête. Quelle est votre réponse ?' }, options: [{ id: 'a', text: { es: 'Recibir calurosamente al huésped, verificar si hay alguna habitación ya inspeccionada que pueda asignarse (upgrade si es necesario), si no hay ninguna disponible solicitar a housekeeping priorizar su habitación, ofrecer guardar el equipaje, invitarlo al restaurante con un desayuno/café de cortesía y mantenerlo informado del avance', en: 'Warmly welcome the guest, check if any already-inspected room can be assigned (upgrade if needed), if none available ask housekeeping to prioritize their room, offer to store luggage, invite them to the restaurant with a complimentary breakfast/coffee, and keep them informed of progress', fr: 'Accueillir chaleureusement le client, vérifier si une chambre déjà inspectée peut être attribuée (surclassement si nécessaire), sinon demander à l\'entretien de prioriser sa chambre, proposer de garder les bagages, l\'inviter au restaurant avec un petit-déjeuner/café de courtoisie et le tenir informé' }, value: 100 }, { id: 'b', text: { es: 'Informar amablemente que el check-in es a las 3:00 PM y ofrecer guardar el equipaje', en: 'Kindly inform that check-in is at 3:00 PM and offer to store luggage', fr: 'Informer aimablement que le check-in est à 15h00 et proposer de garder les bagages' }, value: 30 }, { id: 'c', text: { es: 'Cobrar un cargo de early check-in y priorizar la limpieza de su habitación', en: 'Charge an early check-in fee and prioritize cleaning their room', fr: 'Facturer un supplément de check-in anticipé et prioriser le nettoyage de la chambre' }, value: 35 }, { id: 'd', text: { es: 'Ofrecer un upgrade gratuito a una suite si alguna está disponible', en: 'Offer a free upgrade to a suite if one is available', fr: 'Offrir un surclassement gratuit en suite si une est disponible' }, value: 50 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  // PMS Systems — multiple-choice
  { id: 'hosp-fda-prof-2', profileId: 'front-desk-agent', categoryId: 'hosp-fda-professional', competencyId: 'hosp-fda-pms-systems', type: 'multiple-choice', content: { es: 'El sistema PMS del hotel se cae durante el check-in de la tarde con 30 huéspedes en fila esperando. No hay estimación de cuándo volverá a funcionar. Usted tiene acceso a la lista de reservas impresa del día pero no puede procesar tarjetas de crédito ni generar llaves electrónicas. ¿Cómo maneja la situación?', en: 'The hotel PMS system goes down during the afternoon check-in rush with 30 guests in line waiting. There is no estimate of when it will be back. You have access to the printed day\'s reservation list but cannot process credit cards or generate electronic keys. How do you handle the situation?', fr: 'Le système PMS de l\'hôtel tombe en panne pendant le rush du check-in de l\'après-midi avec 30 clients en file d\'attente. Il n\'y a pas d\'estimation de retour. Vous avez accès à la liste imprimée des réservations mais ne pouvez pas traiter les cartes de crédit ni générer de clés électroniques. Comment gérez-vous la situation ?' }, options: [{ id: 'a', text: { es: 'Activar el protocolo de contingencia: usar el registro manual con formularios de respaldo, solicitar imprints de tarjetas de crédito o registro de garantía para procesar después, usar llaves maestras o llaves físicas de respaldo si existen, informar a cada huésped de la situación con una disculpa y tiempo estimado, y reportar la incidencia a TI y al gerente de turno', en: 'Activate the contingency protocol: use manual registration with backup forms, request credit card imprints or guarantee records for later processing, use master keys or backup physical keys if available, inform each guest of the situation with an apology and estimated time, and report the incident to IT and the shift manager', fr: 'Activer le protocole de contingence : utiliser l\'enregistrement manuel avec des formulaires de secours, demander des empreintes de cartes de crédit, utiliser des clés maîtresses ou physiques de secours, informer chaque client de la situation et signaler l\'incident au responsable' }, value: 100 }, { id: 'b', text: { es: 'Pedir a los huéspedes que esperen en el lobby hasta que el sistema se restablezca', en: 'Ask guests to wait in the lobby until the system is restored', fr: 'Demander aux clients d\'attendre dans le hall jusqu\'au rétablissement du système' }, value: 15 }, { id: 'c', text: { es: 'Registrar a los huéspedes manualmente pero sin procesar pagos hasta que vuelva el sistema', en: 'Register guests manually but without processing payments until the system returns', fr: 'Enregistrer les clients manuellement mais sans traiter les paiements jusqu\'au retour du système' }, value: 50 }, { id: 'd', text: { es: 'Llamar al soporte técnico del PMS y esperar instrucciones', en: 'Call PMS technical support and wait for instructions', fr: 'Appeler le support technique du PMS et attendre les instructions' }, value: 20 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  // Cash Handling — multiple-choice
  { id: 'hosp-fda-prof-3', profileId: 'front-desk-agent', categoryId: 'hosp-fda-professional', competencyId: 'hosp-fda-cash-handling', type: 'multiple-choice', content: { es: 'Al final de su turno, al cuadrar la caja descubre un faltante de USD 85. Revisando las transacciones del día, encuentra una factura de USD 85 de un huésped de check-out que pagó en efectivo pero la transacción no aparece registrada en el sistema. ¿Cuál es el procedimiento correcto?', en: 'At the end of your shift, when balancing the cash drawer you discover a USD 85 shortfall. Reviewing the day\'s transactions, you find an USD 85 invoice from a checkout guest who paid in cash but the transaction does not appear registered in the system. What is the correct procedure?', fr: 'En fin de quart de travail, en équilibrant la caisse, vous découvrez un manque de 85 USD. En examinant les transactions, vous trouvez une facture de 85 USD d\'un client au check-out qui a payé en espèces mais la transaction n\'apparaît pas dans le système. Quelle est la procédure correcte ?' }, options: [{ id: 'a', text: { es: 'Documentar la discrepancia en el reporte de caja, adjuntar la factura como evidencia, registrar la transacción pendiente en el sistema con nota explicativa, informar al supervisor inmediato, y verificar si el comprobante de pago del huésped coincide con el monto antes de cerrar la caja', en: 'Document the discrepancy in the cash report, attach the invoice as evidence, register the pending transaction in the system with an explanatory note, inform the immediate supervisor, and verify if the guest\'s payment receipt matches the amount before closing the drawer', fr: 'Documenter l\'écart dans le rapport de caisse, joindre la facture comme preuve, enregistrer la transaction en attente dans le système avec une note explicative, informer le superviseur immédiat et vérifier si le reçu du client correspond au montant avant de fermer la caisse' }, value: 100 }, { id: 'b', text: { es: 'Registrar la transacción en el sistema ahora y cuadrar la caja normalmente', en: 'Register the transaction in the system now and balance the drawer normally', fr: 'Enregistrer la transaction dans le système maintenant et équilibrer la caisse normalement' }, value: 45 }, { id: 'c', text: { es: 'Reportar el faltante al supervisor y dejar que él investigue', en: 'Report the shortfall to the supervisor and let them investigate', fr: 'Signaler le manque au superviseur et le laisser enquêter' }, value: 40 }, { id: 'd', text: { es: 'Cubrir el faltante con dinero propio para evitar problemas', en: 'Cover the shortfall with your own money to avoid problems', fr: 'Couvrir le manque avec votre propre argent pour éviter des problèmes' }, value: 5 }], maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  // Front Desk Operations — scale
  { id: 'hosp-fda-prof-4', profileId: 'front-desk-agent', categoryId: 'hosp-fda-professional', competencyId: 'hosp-fda-front-desk-ops', type: 'scale', content: { es: '¿Qué nivel de experiencia tiene realizando procesos de check-in, check-out, asignación de habitaciones y coordinación con housekeeping en un hotel?', en: 'What level of experience do you have performing check-in, check-out, room assignment, and housekeeping coordination processes at a hotel?', fr: 'Quel niveau d\'expérience avez-vous dans les processus de check-in, check-out, attribution de chambres et coordination avec l\'entretien ménager dans un hôtel ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Sin experiencia en recepción hotelera', en: 'No hotel front desk experience', fr: 'Aucune expérience en réception hôtelière' }, max: { es: 'Amplia experiencia en recepción de hoteles de alta ocupación', en: 'Extensive experience in front desk at high-occupancy hotels', fr: 'Vaste expérience en réception d\'hôtels à fort taux d\'occupation' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  // PMS Systems — scenario
  { id: 'hosp-fda-prof-5', profileId: 'front-desk-agent', categoryId: 'hosp-fda-professional', competencyId: 'hosp-fda-pms-systems', type: 'scenario', content: { es: 'Una familia de 4 personas llega al hotel con una reserva confirmada para una habitación doble estándar por 5 noches. Al buscar en el PMS, descubre que la reserva fue cancelada hace 3 días por la OTA (Booking.com) debido a un error de tarjeta de crédito, y el hotel no lo detectó ni contactó al huésped. El hotel está al 95% de ocupación y solo queda disponible una suite junior (USD 80 más cara por noche) y una habitación sencilla. La familia tiene niños pequeños cansados y muestra el email de confirmación original.\nContexto: Son las 9:00 PM. No hay otros hoteles de similar categoría disponibles en la zona.', en: 'A family of 4 arrives at the hotel with a confirmed reservation for a standard double room for 5 nights. When searching the PMS, you discover the reservation was cancelled 3 days ago by the OTA (Booking.com) due to a credit card error, and the hotel did not detect it or contact the guest. The hotel is at 95% occupancy with only a junior suite (USD 80 more per night) and a single room available. The family has tired small children and shows the original confirmation email.\nContext: It is 9:00 PM. No other similar-category hotels are available in the area.', fr: 'Une famille de 4 personnes arrive à l\'hôtel avec une réservation confirmée pour une chambre double standard pour 5 nuits. En cherchant dans le PMS, vous découvrez que la réservation a été annulée il y a 3 jours par l\'OTA (Booking.com) en raison d\'une erreur de carte de crédit, et l\'hôtel ne l\'a pas détecté. L\'hôtel est à 95% d\'occupation avec seulement une suite junior (80 USD de plus par nuit) et une chambre simple disponibles.\nContexte : Il est 21h00. Aucun autre hôtel similaire n\'est disponible dans la zone.' }, rubric: { es: 'Evaluar: (1) Empatía y actitud de servicio ante el error del hotel/OTA, (2) Solución inmediata (asignar la suite junior sin cargo adicional, ya que el error no fue del huésped), (3) Comunicación clara y tranquilizadora con la familia, (4) Reporte del incidente al supervisor y a la OTA, (5) Documentación para prevenir recurrencia, (6) Seguimiento durante la estancia para asegurar satisfacción.', en: 'Evaluate: (1) Empathy and service attitude given the hotel/OTA error, (2) Immediate solution (assign junior suite at no extra charge since the error was not the guest\'s), (3) Clear and reassuring communication with the family, (4) Incident report to supervisor and OTA, (5) Documentation to prevent recurrence, (6) Follow-up during the stay to ensure satisfaction.', fr: 'Évaluer : (1) Empathie et attitude de service face à l\'erreur, (2) Solution immédiate (attribuer la suite sans supplément), (3) Communication claire et rassurante, (4) Rapport d\'incident au superviseur et à l\'OTA, (5) Documentation préventive, (6) Suivi pendant le séjour.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  // Cash Handling — open-text
  { id: 'hosp-fda-prof-6', profileId: 'front-desk-agent', categoryId: 'hosp-fda-professional', competencyId: 'hosp-fda-cash-handling', type: 'open-text', content: { es: 'Un huésped corporativo al momento del check-out cuestiona varios cargos en su factura: dos consumos del minibar que asegura no haber realizado, un cargo de room service a las 2:00 AM que dice no reconocer, y un cargo de spa que fue para otro huésped. La factura total es de USD 2,800 y la empresa del huésped es un cliente corporativo importante. Describa paso a paso cómo manejaría la revisión y resolución de esta disputa de facturación.', en: 'A corporate guest at checkout disputes several charges on their bill: two minibar charges they claim they did not make, a 2:00 AM room service charge they say they do not recognize, and a spa charge that was for another guest. The total bill is USD 2,800 and the guest\'s company is an important corporate client. Describe step by step how you would handle the review and resolution of this billing dispute.', fr: 'Un client corporatif au check-out conteste plusieurs frais sur sa facture : deux consommations du minibar qu\'il dit ne pas avoir faites, un room service à 2h00 du matin qu\'il ne reconnaît pas, et un soin spa facturé à un autre client. La facture totale est de 2 800 USD et l\'entreprise du client est un client corporatif important. Décrivez étape par étape comment vous géreriez la révision et la résolution de ce litige de facturation.' }, rubric: { es: 'Evaluar: (1) Actitud profesional y no confrontacional, (2) Revisión detallada de cada cargo con evidencia del sistema, (3) Verificación cruzada con departamentos (minibar, room service, spa), (4) Corrección inmediata del cargo erróneo del spa, (5) Protocolo para cargos disputados sin evidencia clara, (6) Seguimiento y documentación para prevenir errores futuros.', en: 'Evaluate: (1) Professional and non-confrontational attitude, (2) Detailed review of each charge with system evidence, (3) Cross-verification with departments (minibar, room service, spa), (4) Immediate correction of the erroneous spa charge, (5) Protocol for disputed charges without clear evidence, (6) Follow-up and documentation to prevent future errors.', fr: 'Évaluer : (1) Attitude professionnelle et non confrontationnelle, (2) Examen détaillé de chaque frais, (3) Vérification croisée avec les départements, (4) Correction immédiate du spa, (5) Protocole pour les frais contestés, (6) Suivi et documentation préventive.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

// ============================================================================
// FRONT DESK AGENT — SOFT SKILLS QUESTIONS
// ============================================================================

export const hospFdaSoftSkillsQuestions: Question[] = [
  // Guest Service — multiple-choice
  { id: 'hosp-fda-ss-1', profileId: 'front-desk-agent', categoryId: 'hosp-fda-soft-skills', competencyId: 'hosp-fda-guest-service', type: 'multiple-choice', content: { es: 'Un huésped con discapacidad visual llega solo al hotel y necesita asistencia para orientarse en las instalaciones. No solicitó servicios especiales al reservar. ¿Cuál es su enfoque?', en: 'A visually impaired guest arrives alone at the hotel and needs assistance navigating the facilities. They did not request special services when booking. What is your approach?', fr: 'Un client malvoyant arrive seul à l\'hôtel et a besoin d\'aide pour s\'orienter dans les installations. Il n\'a pas demandé de services spéciaux lors de la réservation. Quelle est votre approche ?' }, options: [{ id: 'a', text: { es: 'Presentarse amablemente, preguntar al huésped qué tipo de asistencia prefiere (respetando su autonomía), acompañarlo personalmente a la habitación describiendo el recorrido, explicar la disposición de la habitación y los controles, proporcionar su número directo de recepción, informar a todos los departamentos de servicio, y anotar las preferencias en el perfil del PMS', en: 'Introduce yourself kindly, ask the guest what type of assistance they prefer (respecting their autonomy), personally escort them to the room describing the route, explain the room layout and controls, provide your direct front desk number, inform all service departments, and note preferences in the PMS profile', fr: 'Se présenter aimablement, demander au client quelle assistance il préfère (en respectant son autonomie), l\'accompagner personnellement à la chambre en décrivant le parcours, expliquer la disposition de la chambre et les commandes, fournir le numéro direct de la réception, informer tous les départements et noter les préférences dans le PMS' }, value: 100 }, { id: 'b', text: { es: 'Llamar al botones para que lo acompañe a la habitación y le explique las instalaciones', en: 'Call the bellboy to escort them to the room and explain the facilities', fr: 'Appeler le groom pour l\'accompagner à la chambre et lui expliquer les installations' }, value: 45 }, { id: 'c', text: { es: 'Asignarle la habitación más cercana a la recepción para facilitar su acceso', en: 'Assign them the room closest to reception to facilitate access', fr: 'Lui attribuer la chambre la plus proche de la réception pour faciliter l\'accès' }, value: 35 }, { id: 'd', text: { es: 'Procesar el check-in normalmente y ofrecer ayuda solo si el huésped la solicita', en: 'Process check-in normally and offer help only if the guest requests it', fr: 'Traiter le check-in normalement et offrir de l\'aide uniquement si le client la demande' }, value: 20 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  // Conflict Resolution — multiple-choice
  { id: 'hosp-fda-ss-2', profileId: 'front-desk-agent', categoryId: 'hosp-fda-soft-skills', competencyId: 'hosp-fda-conflict-resolution', type: 'multiple-choice', content: { es: 'Un huésped llega a recepción a las 11:00 PM extremadamente molesto porque la habitación de al lado tiene una fiesta ruidosa. Es la tercera vez que llama en 2 horas. Las dos veces anteriores, seguridad habló con los ocupantes de la habitación ruidosa y estos bajaron el volumen temporalmente, pero volvieron a subir. El huésped amenaza con irse y publicar una reseña negativa. ¿Qué hace?', en: 'A guest comes to the front desk at 11:00 PM extremely upset because the adjacent room is having a noisy party. This is the third time they have called in 2 hours. The previous two times, security spoke with the noisy room occupants who temporarily lowered the volume but raised it again. The guest threatens to leave and post a negative review. What do you do?', fr: 'Un client arrive à la réception à 23h00 extrêmement mécontent car la chambre voisine fait une fête bruyante. C\'est la troisième fois qu\'il appelle en 2 heures. Les deux fois précédentes, la sécurité a parlé aux occupants bruyants mais le bruit a repris. Le client menace de partir et de publier un avis négatif. Que faites-vous ?' }, options: [{ id: 'a', text: { es: 'Disculparse sinceramente con el huésped, cambiarle inmediatamente a una habitación tranquila en otro piso (con upgrade si es posible), enviar seguridad con un último aviso formal a la habitación ruidosa advirtiendo de la política del hotel sobre cancelación de estancia por disturbio, y ofrecer al huésped una compensación por las molestias', en: 'Sincerely apologize to the guest, immediately move them to a quiet room on another floor (with upgrade if possible), send security with a final formal warning to the noisy room advising of the hotel\'s policy on stay cancellation for disturbance, and offer the guest compensation for the inconvenience', fr: 'S\'excuser sincèrement, déplacer immédiatement le client vers une chambre calme sur un autre étage (surclassement si possible), envoyer la sécurité avec un dernier avertissement formel à la chambre bruyante sur la politique d\'annulation de séjour, et offrir une compensation au client' }, value: 100 }, { id: 'b', text: { es: 'Llamar a seguridad por tercera vez y ofrecer tapones para los oídos al huésped', en: 'Call security for the third time and offer earplugs to the guest', fr: 'Appeler la sécurité une troisième fois et offrir des bouchons d\'oreilles au client' }, value: 15 }, { id: 'c', text: { es: 'Cambiar al huésped a otra habitación y disculparse por las molestias', en: 'Move the guest to another room and apologize for the inconvenience', fr: 'Déplacer le client dans une autre chambre et s\'excuser pour les désagréments' }, value: 55 }, { id: 'd', text: { es: 'Informar al huésped que llamará al gerente nocturno para que intervenga directamente', en: 'Inform the guest that you will call the night manager to intervene directly', fr: 'Informer le client que vous allez appeler le directeur de nuit pour intervenir directement' }, value: 40 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  // Guest Service — scale
  { id: 'hosp-fda-ss-3', profileId: 'front-desk-agent', categoryId: 'hosp-fda-soft-skills', competencyId: 'hosp-fda-guest-service', type: 'scale', content: { es: '¿Qué tan natural le resulta anticiparse a las necesidades de los huéspedes antes de que las expresen?', en: 'How natural does it feel for you to anticipate guests\' needs before they express them?', fr: 'À quel point est-il naturel pour vous d\'anticiper les besoins des clients avant qu\'ils ne les expriment ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Generalmente respondo a las solicitudes cuando las recibo', en: 'I generally respond to requests when I receive them', fr: 'Je réponds généralement aux demandes lorsque je les reçois' }, max: { es: 'Anticipar necesidades es parte de mi instinto de servicio; lo hago constantemente', en: 'Anticipating needs is part of my service instinct; I do it constantly', fr: 'Anticiper les besoins fait partie de mon instinct de service ; je le fais constamment' } }, maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  // Teamwork — scale
  { id: 'hosp-fda-ss-4', profileId: 'front-desk-agent', categoryId: 'hosp-fda-soft-skills', competencyId: 'hosp-fda-teamwork', type: 'scale', content: { es: '¿Qué tan efectivo se considera coordinándose con otros departamentos del hotel (housekeeping, mantenimiento, bell service) para resolver solicitudes de huéspedes?', en: 'How effective do you consider yourself at coordinating with other hotel departments (housekeeping, maintenance, bell service) to resolve guest requests?', fr: 'À quel point vous considérez-vous efficace dans la coordination avec d\'autres départements de l\'hôtel (entretien, maintenance, service de bagages) pour résoudre les demandes des clients ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'A veces tengo dificultades para coordinar con otros departamentos', en: 'I sometimes have difficulties coordinating with other departments', fr: 'J\'ai parfois des difficultés à me coordonner avec d\'autres départements' }, max: { es: 'Tengo excelentes relaciones y comunicación fluida con todos los departamentos', en: 'I have excellent relationships and smooth communication with all departments', fr: 'J\'ai d\'excellentes relations et une communication fluide avec tous les départements' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  // Conflict Resolution — ranking
  { id: 'hosp-fda-ss-5', profileId: 'front-desk-agent', categoryId: 'hosp-fda-soft-skills', competencyId: 'hosp-fda-conflict-resolution', type: 'ranking', content: { es: 'Ordene los siguientes pasos por prioridad al manejar un huésped furioso que alza la voz en la recepción:', en: 'Rank the following steps by priority when handling a furious guest who is raising their voice at the front desk:', fr: 'Classez les étapes suivantes par priorité pour gérer un client furieux qui élève la voix à la réception :' }, options: [{ id: 'a', text: { es: 'Mantener la calma y el tono profesional, sin tomar la agresión personalmente', en: 'Stay calm and maintain a professional tone, without taking the aggression personally', fr: 'Rester calme et maintenir un ton professionnel, sans prendre l\'agressivité personnellement' }, value: 1 }, { id: 'b', text: { es: 'Escuchar activamente y validar los sentimientos del huésped', en: 'Actively listen and validate the guest\'s feelings', fr: 'Écouter activement et valider les sentiments du client' }, value: 2 }, { id: 'c', text: { es: 'Ofrecer trasladarse a un área privada para resolver el problema', en: 'Offer to move to a private area to resolve the issue', fr: 'Proposer de se déplacer dans un espace privé pour résoudre le problème' }, value: 3 }, { id: 'd', text: { es: 'Proponer una solución concreta y verificar que sea satisfactoria', en: 'Propose a concrete solution and verify it is satisfactory', fr: 'Proposer une solution concrète et vérifier qu\'elle est satisfaisante' }, value: 4 }], maxScore: 100, aiEvaluated: false, order: 5, isActive: true },
  // Teamwork — open-text
  { id: 'hosp-fda-ss-6', profileId: 'front-desk-agent', categoryId: 'hosp-fda-soft-skills', competencyId: 'hosp-fda-teamwork', type: 'open-text', content: { es: 'Describa una situación (real o hipotética) donde tuvo que coordinarse urgentemente con múltiples departamentos del hotel para resolver un problema de un huésped. ¿Qué departamentos involucró, cómo se comunicó con ellos y cuál fue el resultado?', en: 'Describe a situation (real or hypothetical) where you had to urgently coordinate with multiple hotel departments to solve a guest problem. Which departments did you involve, how did you communicate with them, and what was the outcome?', fr: 'Décrivez une situation (réelle ou hypothétique) où vous avez dû vous coordonner urgemment avec plusieurs départements de l\'hôtel pour résoudre un problème client. Quels départements avez-vous impliqués, comment avez-vous communiqué et quel a été le résultat ?' }, rubric: { es: 'Evaluar: (1) Identificación rápida de los departamentos necesarios, (2) Comunicación clara y urgente con cada equipo, (3) Seguimiento proactivo del avance, (4) Coordinación efectiva sin autoridad jerárquica, (5) Resultado orientado a la satisfacción del huésped, (6) Aprendizaje y mejora de procesos.', en: 'Evaluate: (1) Quick identification of necessary departments, (2) Clear and urgent communication with each team, (3) Proactive progress follow-up, (4) Effective coordination without hierarchical authority, (5) Guest satisfaction-oriented outcome, (6) Learning and process improvement.', fr: 'Évaluer : (1) Identification rapide des départements nécessaires, (2) Communication claire et urgente, (3) Suivi proactif, (4) Coordination efficace sans autorité hiérarchique, (5) Résultat orienté satisfaction client, (6) Apprentissage et amélioration des processus.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

// ============================================================================
// FRONT DESK AGENT — READINESS QUESTIONS
// ============================================================================

export const hospFdaReadinessQuestions: Question[] = [
  // Technology Adoption — multiple-choice
  { id: 'hosp-fda-rd-1', profileId: 'front-desk-agent', categoryId: 'hosp-fda-readiness', competencyId: 'hosp-fda-tech-adoption', type: 'multiple-choice', content: { es: 'El hotel implementará un sistema de check-in mediante kioscos de autoservicio y app móvil. Su rol cambiará de procesar check-ins a ser un "embajador de experiencia" que recibe huéspedes, los guía en el uso del kiosco y brinda servicio personalizado. Algunos colegas se sienten amenazados por la tecnología. ¿Cuál es su actitud?', en: 'The hotel will implement a check-in system via self-service kiosks and mobile app. Your role will change from processing check-ins to being an "experience ambassador" who welcomes guests, guides them through the kiosk, and provides personalized service. Some colleagues feel threatened by the technology. What is your attitude?', fr: 'L\'hôtel mettra en place un système de check-in via des bornes libre-service et une application mobile. Votre rôle passera du traitement des check-ins à celui d\'"ambassadeur d\'expérience" qui accueille les clients, les guide dans l\'utilisation de la borne et fournit un service personnalisé. Certains collègues se sentent menacés par la technologie. Quelle est votre attitude ?' }, options: [{ id: 'a', text: { es: 'Ver la oportunidad de evolucionar: aprender a dominar la nueva tecnología antes del lanzamiento, ofrecerse como "super-usuario" para capacitar a colegas, enfocarse en las habilidades de servicio que la tecnología no puede reemplazar, y apoyar a los colegas preocupados compartiendo la visión positiva del cambio', en: 'See the opportunity to evolve: learn to master the new technology before launch, volunteer as a "super-user" to train colleagues, focus on service skills that technology cannot replace, and support worried colleagues by sharing the positive vision of change', fr: 'Voir l\'opportunité d\'évoluer : maîtriser la nouvelle technologie avant le lancement, se porter volontaire comme "super-utilisateur" pour former les collègues, se concentrer sur les compétences de service que la technologie ne peut remplacer, et soutenir les collègues inquiets' }, value: 100 }, { id: 'b', text: { es: 'Aceptar el cambio porque es una decisión de la gerencia, pero sin entusiasmo particular', en: 'Accept the change because it is a management decision, but without particular enthusiasm', fr: 'Accepter le changement car c\'est une décision de la direction, mais sans enthousiasme particulier' }, value: 35 }, { id: 'c', text: { es: 'Expresar preocupación a la gerencia sobre el impacto en la experiencia del huésped', en: 'Express concern to management about the impact on guest experience', fr: 'Exprimer des préoccupations à la direction sur l\'impact sur l\'expérience client' }, value: 30 }, { id: 'd', text: { es: 'Enfocarse en aprender la tecnología pero dejar que cada colega maneje su propia adaptación', en: 'Focus on learning the technology but let each colleague handle their own adaptation', fr: 'Se concentrer sur l\'apprentissage de la technologie mais laisser chaque collègue gérer sa propre adaptation' }, value: 45 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  // Service Evolution — multiple-choice
  { id: 'hosp-fda-rd-2', profileId: 'front-desk-agent', categoryId: 'hosp-fda-readiness', competencyId: 'hosp-fda-service-evolution', type: 'multiple-choice', content: { es: 'El hotel recibe cada vez más huéspedes que reservan a través de Airbnb Experiences y esperan un servicio menos formal y más "auténtico". Piden recomendaciones de lugares locales no turísticos, quieren interactuar como si usted fuera un amigo local, y algunos se quejan de que el servicio es "demasiado corporativo". Sin embargo, otros huéspedes (corporativos y de lujo) esperan el servicio formal tradicional. ¿Cómo adapta su estilo de servicio?', en: 'The hotel is receiving more and more guests who book through Airbnb Experiences and expect a less formal, more "authentic" service. They ask for recommendations of non-touristy local places, want to interact as if you were a local friend, and some complain the service is "too corporate." However, other guests (corporate and luxury) expect traditional formal service. How do you adapt your service style?', fr: 'L\'hôtel reçoit de plus en plus de clients qui réservent via Airbnb Experiences et attendent un service moins formel et plus "authentique." Ils demandent des recommandations de lieux locaux non touristiques et certains se plaignent que le service est "trop corporate." Cependant, d\'autres clients attendent le service formel traditionnel. Comment adaptez-vous votre style de service ?' }, options: [{ id: 'a', text: { es: 'Desarrollar la habilidad de "leer" a cada huésped y adaptar el estilo: preparar una guía personal de recomendaciones locales auténticas, aprender a cambiar entre el tono formal y el casual según el perfil, mantener el profesionalismo como base pero ajustar la calidez y cercanía según cada interacción', en: 'Develop the ability to "read" each guest and adapt the style: prepare a personal guide of authentic local recommendations, learn to switch between formal and casual tone based on profile, maintain professionalism as a base but adjust warmth and closeness for each interaction', fr: 'Développer la capacité de "lire" chaque client et adapter le style : préparer un guide personnel de recommandations locales authentiques, apprendre à alterner entre le ton formel et décontracté selon le profil, maintenir le professionnalisme comme base mais ajuster la chaleur et la proximité' }, value: 100 }, { id: 'b', text: { es: 'Mantener el estilo de servicio formal estándar para todos los huéspedes por consistencia', en: 'Maintain the standard formal service style for all guests for consistency', fr: 'Maintenir le style de service formel standard pour tous les clients par souci de cohérence' }, value: 25 }, { id: 'c', text: { es: 'Adoptar un estilo más casual para todos los huéspedes ya que es la tendencia actual', en: 'Adopt a more casual style for all guests since it is the current trend', fr: 'Adopter un style plus décontracté pour tous les clients puisque c\'est la tendance actuelle' }, value: 20 }, { id: 'd', text: { es: 'Preguntar directamente a cada huésped al check-in qué tipo de servicio prefiere', en: 'Directly ask each guest at check-in what type of service they prefer', fr: 'Demander directement à chaque client au check-in quel type de service il préfère' }, value: 45 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  // Technology Adoption — scale
  { id: 'hosp-fda-rd-3', profileId: 'front-desk-agent', categoryId: 'hosp-fda-readiness', competencyId: 'hosp-fda-tech-adoption', type: 'scale', content: { es: '¿Qué tan rápido aprende a utilizar nuevos sistemas informáticos y herramientas tecnológicas?', en: 'How quickly do you learn to use new computer systems and technological tools?', fr: 'À quelle vitesse apprenez-vous à utiliser de nouveaux systèmes informatiques et outils technologiques ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Necesito tiempo y capacitación formal para aprender nuevas herramientas', en: 'I need time and formal training to learn new tools', fr: 'J\'ai besoin de temps et de formation formelle pour apprendre de nouveaux outils' }, max: { es: 'Aprendo sistemas nuevos de forma autodidacta y con rapidez', en: 'I learn new systems in a self-taught manner and quickly', fr: 'J\'apprends les nouveaux systèmes de manière autodidacte et rapidement' } }, maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  // Multilingual — scale
  { id: 'hosp-fda-rd-4', profileId: 'front-desk-agent', categoryId: 'hosp-fda-readiness', competencyId: 'hosp-fda-multilingual', type: 'scale', content: { es: '¿Qué tan dispuesto está a aprender idiomas adicionales o mejorar sus habilidades lingüísticas para atender huéspedes internacionales?', en: 'How willing are you to learn additional languages or improve your language skills to serve international guests?', fr: 'À quel point êtes-vous disposé à apprendre des langues supplémentaires ou à améliorer vos compétences linguistiques pour servir des clients internationaux ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Me conformo con los idiomas que ya hablo', en: 'I am content with the languages I already speak', fr: 'Je me contente des langues que je parle déjà' }, max: { es: 'Estudio activamente idiomas y busco practicar con huéspedes internacionales', en: 'I actively study languages and seek to practice with international guests', fr: 'J\'étudie activement des langues et cherche à pratiquer avec des clients internationaux' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  // Service Evolution — scenario
  { id: 'hosp-fda-rd-5', profileId: 'front-desk-agent', categoryId: 'hosp-fda-readiness', competencyId: 'hosp-fda-service-evolution', type: 'scenario', content: { es: 'El hotel acaba de recibir una certificación de "Hotel Pet-Friendly" y comenzará a aceptar mascotas en habitaciones designadas. Usted no tiene experiencia con animales en hoteles y algunos compañeros expresan preocupación por alergias y limpieza. Un huésped llega al check-in con dos perros grandes y un gato en transportadora. No reservó habitación pet-friendly y las 10 habitaciones designadas están ocupadas. Las políticas del hotel permiten máximo una mascota por habitación.\nContexto: El huésped viaja para una exhibición canina y dice que todos los hoteles de la zona aceptan mascotas.', en: 'The hotel has just received a "Pet-Friendly Hotel" certification and will begin accepting pets in designated rooms. You have no experience with animals in hotels and some colleagues express concerns about allergies and cleanliness. A guest arrives at check-in with two large dogs and a cat in a carrier. They did not book a pet-friendly room and all 10 designated rooms are occupied. Hotel policy allows a maximum of one pet per room.\nContext: The guest is traveling for a dog show and says all area hotels accept pets.', fr: 'L\'hôtel vient de recevoir une certification "Hôtel Pet-Friendly" et commencera à accepter les animaux dans des chambres désignées. Vous n\'avez pas d\'expérience avec les animaux en hôtel. Un client arrive au check-in avec deux grands chiens et un chat. Il n\'a pas réservé de chambre pet-friendly et les 10 chambres désignées sont occupées. La politique de l\'hôtel autorise un maximum d\'un animal par chambre.\nContexte : Le client voyage pour une exposition canine et dit que tous les hôtels de la zone acceptent les animaux.' }, rubric: { es: 'Evaluar: (1) Actitud de servicio positiva ante una situación nueva e inesperada, (2) Conocimiento y aplicación de las nuevas políticas pet-friendly, (3) Solución creativa dentro de las normas (contactar supervisor, buscar opciones), (4) Comunicación empática con el huésped sobre las limitaciones, (5) Coordinación con otros departamentos/hoteles si es necesario, (6) Disposición para adaptarse a la nueva realidad del hotel.', en: 'Evaluate: (1) Positive service attitude in a new and unexpected situation, (2) Knowledge and application of new pet-friendly policies, (3) Creative solution within guidelines (contact supervisor, find options), (4) Empathetic communication with the guest about limitations, (5) Coordination with other departments/hotels if needed, (6) Willingness to adapt to the hotel\'s new reality.', fr: 'Évaluer : (1) Attitude de service positive face à une situation nouvelle, (2) Connaissance des nouvelles politiques pet-friendly, (3) Solution créative dans les règles, (4) Communication empathique sur les limitations, (5) Coordination avec d\'autres départements/hôtels, (6) Volonté de s\'adapter.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  // Multilingual — open-text
  { id: 'hosp-fda-rd-6', profileId: 'front-desk-agent', categoryId: 'hosp-fda-readiness', competencyId: 'hosp-fda-multilingual', type: 'open-text', content: { es: 'Un grupo de 8 huéspedes llega al hotel. Hablan japonés y no hablan español ni inglés. No hay ningún empleado que hable japonés en el hotel en ese momento. Los huéspedes se ven confundidos y algo frustrados. Describa cómo manejaría la comunicación para completar el check-in, hacerlos sentir bienvenidos y asegurar que comprendan la información esencial de su estancia.', en: 'A group of 8 guests arrives at the hotel. They speak Japanese and do not speak Spanish or English. No employee speaks Japanese at the hotel at that moment. The guests look confused and somewhat frustrated. Describe how you would handle communication to complete check-in, make them feel welcome, and ensure they understand essential information about their stay.', fr: 'Un groupe de 8 clients arrive à l\'hôtel. Ils parlent japonais et ne parlent ni espagnol ni anglais. Aucun employé ne parle japonais à cet instant. Les clients semblent confus et quelque peu frustrés. Décrivez comment vous géreriez la communication pour compléter le check-in, les faire se sentir bienvenus et vous assurer qu\'ils comprennent les informations essentielles de leur séjour.' }, rubric: { es: 'Evaluar: (1) Uso creativo de herramientas de traducción (apps, Google Translate, traducción visual), (2) Comunicación no verbal: sonrisas, gestos, señales, (3) Preparación de material visual/escrito multilingüe, (4) Paciencia y calidez genuina, (5) Anticipación de necesidades culturales, (6) Seguimiento durante la estancia para facilitar la comunicación.', en: 'Evaluate: (1) Creative use of translation tools (apps, Google Translate, visual translation), (2) Non-verbal communication: smiles, gestures, signals, (3) Preparation of multilingual visual/written material, (4) Patience and genuine warmth, (5) Anticipation of cultural needs, (6) Follow-up during the stay to facilitate communication.', fr: 'Évaluer : (1) Utilisation créative d\'outils de traduction, (2) Communication non verbale, (3) Préparation de matériel multilingue, (4) Patience et chaleur authentique, (5) Anticipation des besoins culturels, (6) Suivi pendant le séjour.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

// ============================================================================
// CHEF / KITCHEN MANAGER — PROFESSIONAL QUESTIONS
// ============================================================================

export const hospCkmProfessionalQuestions: Question[] = [
  // Culinary Expertise — multiple-choice
  { id: 'hosp-ckm-prof-1', profileId: 'chef-kitchen-manager', categoryId: 'hosp-ckm-professional', competencyId: 'hosp-ckm-culinary-expertise', type: 'multiple-choice', content: { es: 'El hotel le solicita diseñar un nuevo menú para el restaurante principal. El concepto actual (cocina internacional genérica) tiene críticas por ser "poco memorable". Los datos muestran que el 60% de los huéspedes son turistas internacionales que buscan experiencias gastronómicas locales, mientras el 40% son ejecutivos locales que almuerzan regularmente. ¿Cuál es su enfoque para el nuevo menú?', en: 'The hotel asks you to design a new menu for the main restaurant. The current concept (generic international cuisine) is criticized as "unmemorable." Data shows 60% of guests are international tourists seeking local gastronomic experiences, while 40% are local executives who lunch regularly. What is your approach for the new menu?', fr: 'L\'hôtel vous demande de concevoir un nouveau menu pour le restaurant principal. Le concept actuel (cuisine internationale générique) est critiqué comme "peu mémorable." Les données montrent que 60% des clients sont des touristes internationaux cherchant des expériences gastronomiques locales, tandis que 40% sont des cadres locaux qui déjeunent régulièrement. Quelle est votre approche pour le nouveau menu ?' }, options: [{ id: 'a', text: { es: 'Crear un concepto de "cocina local contemporánea" que satisfaga ambos segmentos: platillos insignia basados en ingredientes y técnicas locales con presentación moderna, opciones de almuerzo ejecutivo eficiente, carta rotativa estacional, maridaje con productos locales, y mantener 3-4 opciones internacionales universales como plan de seguridad', en: 'Create a "contemporary local cuisine" concept that satisfies both segments: signature dishes based on local ingredients and techniques with modern presentation, efficient executive lunch options, seasonal rotating menu, pairing with local products, and maintain 3-4 universal international options as a safety net', fr: 'Créer un concept de "cuisine locale contemporaine" satisfaisant les deux segments : plats signature basés sur des ingrédients et techniques locaux avec une présentation moderne, options de déjeuner exécutif efficace, carte saisonnière rotative, accords avec des produits locaux, et maintenir 3-4 options internationales universelles' }, value: 100 }, { id: 'b', text: { es: 'Enfocarse completamente en cocina local tradicional para diferenciarse de la competencia', en: 'Focus entirely on traditional local cuisine to differentiate from the competition', fr: 'Se concentrer entièrement sur la cuisine locale traditionnelle pour se différencier de la concurrence' }, value: 40 }, { id: 'c', text: { es: 'Mantener la cocina internacional pero mejorar la calidad de los ingredientes y la presentación', en: 'Keep international cuisine but improve ingredient quality and presentation', fr: 'Garder la cuisine internationale mais améliorer la qualité des ingrédients et la présentation' }, value: 30 }, { id: 'd', text: { es: 'Crear dos menús separados: uno local para turistas y uno internacional para ejecutivos', en: 'Create two separate menus: one local for tourists and one international for executives', fr: 'Créer deux menus séparés : un local pour les touristes et un international pour les cadres' }, value: 35 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  // Kitchen Management — multiple-choice
  { id: 'hosp-ckm-prof-2', profileId: 'chef-kitchen-manager', categoryId: 'hosp-ckm-professional', competencyId: 'hosp-ckm-kitchen-management', type: 'multiple-choice', content: { es: 'Al realizar el inventario semanal, descubre que el proveedor principal de proteínas (que representa el 40% de sus compras) ha entregado cortes de carne con calidad significativamente inferior a la habitual en las últimas 3 entregas. Al contactarlo, admite que cambió de frigorífico proveedor sin informarle. Usted tiene un evento para 200 personas en 4 días. ¿Cómo procede?', en: 'During the weekly inventory, you discover that your main protein supplier (representing 40% of your purchases) has delivered significantly lower quality meat cuts in the last 3 deliveries. When contacted, they admit they changed their supplying cold storage without informing you. You have an event for 200 people in 4 days. How do you proceed?', fr: 'Lors de l\'inventaire hebdomadaire, vous découvrez que votre fournisseur principal de protéines (40% de vos achats) a livré des viandes de qualité significativement inférieure lors des 3 dernières livraisons. Il admet avoir changé de fournisseur de chambre froide sans vous informer. Vous avez un événement pour 200 personnes dans 4 jours. Comment procédez-vous ?' }, options: [{ id: 'a', text: { es: 'Activar proveedores alternativos inmediatamente para el evento, exigir al proveedor principal una explicación formal y garantía de retorno a la calidad original, negociar crédito o descuento por las entregas deficientes, establecer un protocolo de inspección de calidad en cada recepción, y diversificar la base de proveedores para reducir la dependencia', en: 'Activate alternative suppliers immediately for the event, demand a formal explanation from the main supplier and guarantee of return to original quality, negotiate credit or discount for deficient deliveries, establish a quality inspection protocol for each receiving, and diversify the supplier base to reduce dependency', fr: 'Activer des fournisseurs alternatifs immédiatement pour l\'événement, exiger une explication formelle et une garantie de retour à la qualité, négocier un crédit pour les livraisons déficientes, établir un protocole d\'inspection qualité à chaque réception et diversifier la base de fournisseurs' }, value: 100 }, { id: 'b', text: { es: 'Cambiar de proveedor de proteínas inmediatamente y buscar uno nuevo', en: 'Change protein suppliers immediately and find a new one', fr: 'Changer de fournisseur de protéines immédiatement et en trouver un nouveau' }, value: 40 }, { id: 'c', text: { es: 'Dar una última oportunidad al proveedor exigiendo que la siguiente entrega sea de la calidad original', en: 'Give the supplier one last chance demanding the next delivery meet original quality', fr: 'Donner une dernière chance au fournisseur en exigeant que la prochaine livraison soit de qualité originale' }, value: 25 }, { id: 'd', text: { es: 'Adaptar el menú del evento para usar las proteínas disponibles y minimizar el riesgo', en: 'Adapt the event menu to use available proteins and minimize risk', fr: 'Adapter le menu de l\'événement pour utiliser les protéines disponibles et minimiser le risque' }, value: 35 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  // Food Safety — multiple-choice
  { id: 'hosp-ckm-prof-3', profileId: 'chef-kitchen-manager', categoryId: 'hosp-ckm-professional', competencyId: 'hosp-ckm-food-safety', type: 'multiple-choice', content: { es: 'Durante el servicio de la noche, un cocinero le reporta que la cámara de refrigeración de lácteos y salsas ha estado a 12°C (temperatura segura máxima: 4°C) durante las últimas 3 horas por una falla en el compresor. Adentro hay: crema para 40 postres del día siguiente, 15 kg de quesos para el brunch del domingo, salsas madres preparadas hoy, y mantequilla compuesta para el servicio de mañana. ¿Cuál es su decisión?', en: 'During evening service, a cook reports that the dairy and sauce refrigerator has been at 12°C (maximum safe temperature: 4°C) for the past 3 hours due to a compressor failure. Inside there is: cream for 40 desserts for tomorrow, 15 kg of cheese for Sunday brunch, mother sauces prepared today, and compound butter for tomorrow\'s service. What is your decision?', fr: 'Pendant le service du soir, un cuisinier vous signale que le réfrigérateur des produits laitiers et sauces est à 12°C (température maximale sûre : 4°C) depuis 3 heures à cause d\'une panne du compresseur. À l\'intérieur : crème pour 40 desserts de demain, 15 kg de fromages pour le brunch de dimanche, sauces mères préparées aujourd\'hui et beurre composé pour demain. Quelle est votre décision ?' }, options: [{ id: 'a', text: { es: 'Descartar todos los productos que estuvieron en la zona de peligro (4-60°C) por más de 2 horas (la crema, salsas y mantequilla compuesta), evaluar los quesos duros que pueden tolerar mejor, trasladar lo salvable a otra cámara, llamar a mantenimiento de emergencia para el compresor, activar pedido urgente de reposición para el servicio de mañana, y documentar el incidente completo', en: 'Discard all products that were in the danger zone (4-60°C) for more than 2 hours (cream, sauces, and compound butter), evaluate hard cheeses that may tolerate better, transfer salvageable items to another unit, call emergency maintenance for the compressor, activate urgent restocking for tomorrow\'s service, and document the complete incident', fr: 'Éliminer tous les produits dans la zone de danger (4-60°C) depuis plus de 2 heures (crème, sauces, beurre composé), évaluer les fromages à pâte dure, transférer les produits récupérables, appeler la maintenance d\'urgence, activer le réapprovisionnement urgent et documenter l\'incident' }, value: 100 }, { id: 'b', text: { es: 'Trasladar todo a otra cámara refrigerada y evaluar mañana si los productos están bien', en: 'Transfer everything to another refrigerator and evaluate tomorrow if the products are fine', fr: 'Tout transférer dans un autre réfrigérateur et évaluer demain si les produits sont bons' }, value: 15 }, { id: 'c', text: { es: 'Descartar solo la crema y las salsas (los más perecederos) y conservar los quesos y la mantequilla', en: 'Discard only the cream and sauces (the most perishable) and keep the cheeses and butter', fr: 'Éliminer uniquement la crème et les sauces (les plus périssables) et conserver les fromages et le beurre' }, value: 45 }, { id: 'd', text: { es: 'Oler y probar cada producto para determinar si aún está en condiciones de uso', en: 'Smell and taste each product to determine if it is still usable', fr: 'Sentir et goûter chaque produit pour déterminer s\'il est encore utilisable' }, value: 5 }], maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  // Culinary Expertise — scale
  { id: 'hosp-ckm-prof-4', profileId: 'chef-kitchen-manager', categoryId: 'hosp-ckm-professional', competencyId: 'hosp-ckm-culinary-expertise', type: 'scale', content: { es: '¿Qué nivel de dominio tiene en el diseño de menús que balanceen creatividad gastronómica, costos, eficiencia de producción y preferencias del mercado objetivo?', en: 'What level of mastery do you have in designing menus that balance gastronomic creativity, costs, production efficiency, and target market preferences?', fr: 'Quel niveau de maîtrise avez-vous dans la conception de menus qui équilibrent créativité gastronomique, coûts, efficacité de production et préférences du marché cible ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Experiencia limitada en diseño de menú integral', en: 'Limited experience in comprehensive menu design', fr: 'Expérience limitée en conception de menu intégral' }, max: { es: 'Domino el diseño de menú como herramienta estratégica del negocio', en: 'I master menu design as a strategic business tool', fr: 'Je maîtrise la conception de menu comme outil stratégique de l\'entreprise' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  // Kitchen Management — scenario
  { id: 'hosp-ckm-prof-5', profileId: 'chef-kitchen-manager', categoryId: 'hosp-ckm-professional', competencyId: 'hosp-ckm-kitchen-management', type: 'scenario', content: { es: 'El hotel donde trabaja será sede de una boda para 300 personas este sábado. El menú fue acordado hace 2 meses: entrada de langosta, plato fuerte de filete mignon, y postre de fondant de chocolate. El miércoles recibe la llamada de la organizadora informando que 45 de los invitados son veganos (no estaba en el acuerdo original), 12 son celíacos, y la novia decidió cambiar el postre a una torre de profiteroles personalizada. Además, su sous chef renunció ayer.\nContexto: Su brigada regular es de 8 cocineros. El presupuesto del evento ya está cerrado. El hotel tiene reputación de bodas de lujo.', en: 'The hotel where you work will host a wedding for 300 people this Saturday. The menu was agreed 2 months ago: lobster starter, filet mignon main course, and chocolate fondant dessert. On Wednesday you receive a call from the planner informing you that 45 guests are vegan (not in the original agreement), 12 are celiac, and the bride decided to change the dessert to a personalized profiterole tower. Additionally, your sous chef resigned yesterday.\nContext: Your regular brigade is 8 cooks. The event budget is already closed. The hotel has a luxury wedding reputation.', fr: 'L\'hôtel accueillera un mariage pour 300 personnes samedi. Le menu a été convenu il y a 2 mois. Mercredi, l\'organisatrice vous informe que 45 invités sont végans, 12 sont cœliaques, et la mariée veut changer le dessert. De plus, votre sous-chef a démissionné hier.\nContexte : Votre brigade régulière est de 8 cuisiniers. Le budget est fermé. L\'hôtel a une réputation de mariages de luxe.' }, rubric: { es: 'Evaluar: (1) Gestión de los cambios de último momento sin comprometer la calidad, (2) Diseño de alternativas veganas y sin gluten al nivel del evento original, (3) Solución para el postre personalizado con el tiempo disponible, (4) Reorganización de la brigada sin sous chef (reasignar roles, traer personal extra), (5) Comunicación con la organizadora sobre costos adicionales, (6) Plan de producción detallado para los 3 días restantes.', en: 'Evaluate: (1) Last-minute change management without compromising quality, (2) Design of vegan and gluten-free alternatives at original event level, (3) Customized dessert solution within available time, (4) Brigade reorganization without sous chef (reassign roles, bring extra staff), (5) Communication with planner about additional costs, (6) Detailed production plan for the remaining 3 days.', fr: 'Évaluer : (1) Gestion des changements de dernière minute, (2) Alternatives véganes et sans gluten au niveau de l\'événement, (3) Solution pour le dessert personnalisé, (4) Réorganisation de la brigade, (5) Communication sur les coûts supplémentaires, (6) Plan de production détaillé.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  // Food Safety — open-text
  { id: 'hosp-ckm-prof-6', profileId: 'chef-kitchen-manager', categoryId: 'hosp-ckm-professional', competencyId: 'hosp-ckm-food-safety', type: 'open-text', content: { es: 'Usted acaba de ser contratado como chef ejecutivo de un hotel que no cuenta con un sistema HACCP formalizado. La cocina opera con prácticas informales de seguridad alimentaria. Describa su plan para implementar un sistema HACCP completo, incluyendo las etapas, los puntos críticos de control que priorizaría, cómo capacitaría al equipo y qué documentación establecería.', en: 'You have just been hired as executive chef of a hotel that does not have a formalized HACCP system. The kitchen operates with informal food safety practices. Describe your plan to implement a complete HACCP system, including the stages, the critical control points you would prioritize, how you would train the team, and what documentation you would establish.', fr: 'Vous venez d\'être embauché comme chef exécutif d\'un hôtel qui n\'a pas de système HACCP formalisé. La cuisine fonctionne avec des pratiques informelles de sécurité alimentaire. Décrivez votre plan pour mettre en œuvre un système HACCP complet, incluant les étapes, les points critiques de contrôle que vous prioriseriez, comment vous formeriez l\'équipe et quelle documentation vous établiriez.' }, rubric: { es: 'Evaluar: (1) Conocimiento de los 7 principios HACCP, (2) Análisis de peligros específicos de la operación, (3) Identificación de puntos críticos de control (recepción, almacenamiento, cocción, enfriamiento, servicio), (4) Establecimiento de límites críticos y acciones correctivas, (5) Plan de capacitación progresivo para todo el equipo, (6) Sistema de documentación y registros (bitácoras de temperatura, listas de verificación, registros de incidentes).', en: 'Evaluate: (1) Knowledge of the 7 HACCP principles, (2) Hazard analysis specific to the operation, (3) Identification of critical control points (receiving, storage, cooking, cooling, service), (4) Establishing critical limits and corrective actions, (5) Progressive training plan for the entire team, (6) Documentation and record system (temperature logs, checklists, incident reports).', fr: 'Évaluer : (1) Connaissance des 7 principes HACCP, (2) Analyse des dangers spécifiques, (3) Identification des points critiques de contrôle, (4) Limites critiques et actions correctives, (5) Plan de formation progressif, (6) Système de documentation et registres.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

// ============================================================================
// CHEF / KITCHEN MANAGER — SOFT SKILLS QUESTIONS
// ============================================================================

export const hospCkmSoftSkillsQuestions: Question[] = [
  // Brigade Leadership — multiple-choice
  { id: 'hosp-ckm-ss-1', profileId: 'chef-kitchen-manager', categoryId: 'hosp-ckm-soft-skills', competencyId: 'hosp-ckm-brigade-leadership', type: 'multiple-choice', content: { es: 'Un cocinero de línea con 5 años de experiencia y buen desempeño técnico ha comenzado a mostrar una actitud negativa: llega tarde frecuentemente, discute con compañeros durante el servicio y hace comentarios despectivos sobre los platillos nuevos del menú. Otros cocineros están incómodos con su comportamiento. ¿Cómo maneja la situación?', en: 'A line cook with 5 years of experience and good technical performance has started showing a negative attitude: frequently arriving late, arguing with colleagues during service, and making disparaging comments about new menu dishes. Other cooks are uncomfortable with his behavior. How do you handle the situation?', fr: 'Un cuisinier de ligne avec 5 ans d\'expérience et de bonnes performances techniques a commencé à montrer une attitude négative : retards fréquents, disputes avec les collègues pendant le service et commentaires désobligeants sur les nouveaux plats. Les autres cuisiniers sont gênés par son comportement. Comment gérez-vous la situation ?' }, options: [{ id: 'a', text: { es: 'Tener una conversación privada y directa: reconocer su valor técnico, exponer los comportamientos observados con ejemplos específicos, preguntar si hay algo que le esté afectando (personal o laboral), establecer expectativas claras de conducta, acordar un plan de mejora con seguimiento, y dejar claro las consecuencias de no mejorar', en: 'Have a private and direct conversation: acknowledge their technical value, present observed behaviors with specific examples, ask if something is affecting them (personal or work), set clear conduct expectations, agree on an improvement plan with follow-up, and make clear the consequences of not improving', fr: 'Avoir une conversation privée et directe : reconnaître sa valeur technique, présenter les comportements observés avec des exemples spécifiques, demander si quelque chose l\'affecte, établir des attentes claires de conduite, convenir d\'un plan d\'amélioration avec suivi et clarifier les conséquences' }, value: 100 }, { id: 'b', text: { es: 'Darle una amonestación formal por escrito y documentar su comportamiento', en: 'Give a formal written warning and document their behavior', fr: 'Donner un avertissement formel écrit et documenter son comportement' }, value: 40 }, { id: 'c', text: { es: 'Hablar con el equipo para entender mejor la situación antes de confrontar al cocinero', en: 'Talk to the team to better understand the situation before confronting the cook', fr: 'Parler à l\'équipe pour mieux comprendre la situation avant de confronter le cuisinier' }, value: 35 }, { id: 'd', text: { es: 'Ignorar el problema temporalmente y esperar a ver si mejora por sí solo', en: 'Temporarily ignore the problem and wait to see if it improves on its own', fr: 'Ignorer temporairement le problème et attendre pour voir s\'il s\'améliore de lui-même' }, value: 10 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  // Stress Management — multiple-choice
  { id: 'hosp-ckm-ss-2', profileId: 'chef-kitchen-manager', categoryId: 'hosp-ckm-soft-skills', competencyId: 'hosp-ckm-stress-management', type: 'multiple-choice', content: { es: 'Es sábado por la noche, el restaurante tiene 120 comensales, y ocurre lo siguiente simultáneamente: (1) el horno principal se avería con 20 platillos pendientes de cocción, (2) un cocinero se corta y debe ir a urgencias, (3) una mesa VIP de 8 personas envía de vuelta los entrantes diciendo que están fríos, y (4) el mesero informa que un cliente tiene una reacción alérgica leve a un platillo. ¿Cuál es su prioridad inmediata?', en: 'It\'s Saturday night, the restaurant has 120 diners, and the following happens simultaneously: (1) the main oven breaks down with 20 dishes pending cooking, (2) a cook cuts themselves and must go to the ER, (3) a VIP table of 8 sends back starters saying they are cold, and (4) the server reports a customer is having a mild allergic reaction to a dish. What is your immediate priority?', fr: 'C\'est samedi soir, le restaurant a 120 convives, et les événements suivants se produisent simultanément : (1) le four principal tombe en panne avec 20 plats en attente, (2) un cuisinier se coupe et doit aller aux urgences, (3) une table VIP de 8 personnes renvoie les entrées froides, et (4) un client a une réaction allergique légère à un plat. Quelle est votre priorité immédiate ?' }, options: [{ id: 'a', text: { es: 'Priorizar por seguridad: (1) Atender la reacción alérgica inmediatamente (enviar al gerente con el cliente, verificar el platillo), (2) Asegurar que el cocinero herido reciba atención, (3) Reasignar los platillos del horno a otros equipos de cocción, (4) Rehacer los entrantes de la mesa VIP personalmente. Todo delegando con instrucciones claras y breves a cada miembro del equipo', en: 'Prioritize by safety: (1) Address the allergic reaction immediately (send manager to the customer, verify the dish), (2) Ensure the injured cook receives care, (3) Reassign oven dishes to other cooking equipment, (4) Personally redo the VIP table starters. All while delegating with clear and brief instructions to each team member', fr: 'Prioriser par sécurité : (1) Traiter la réaction allergique immédiatement, (2) S\'assurer que le cuisinier blessé reçoive des soins, (3) Réaffecter les plats du four à d\'autres équipements, (4) Refaire personnellement les entrées VIP. Le tout en déléguant avec des instructions claires et brèves' }, value: 100 }, { id: 'b', text: { es: 'Enfocarse en solucionar el horno porque afecta a 20 platillos y luego atender lo demás', en: 'Focus on fixing the oven because it affects 20 dishes and then handle the rest', fr: 'Se concentrer sur la réparation du four car il affecte 20 plats puis traiter le reste' }, value: 20 }, { id: 'c', text: { es: 'Atender la mesa VIP primero porque genera el mayor impacto en reputación', en: 'Attend to the VIP table first because it generates the biggest reputation impact', fr: 'S\'occuper de la table VIP en premier car elle génère le plus grand impact sur la réputation' }, value: 25 }, { id: 'd', text: { es: 'Delegar todo al sous chef (si lo hay) y enfocarse solo en la reacción alérgica', en: 'Delegate everything to the sous chef (if available) and focus only on the allergic reaction', fr: 'Tout déléguer au sous-chef (s\'il y en a un) et se concentrer uniquement sur la réaction allergique' }, value: 45 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  // Brigade Leadership — scale
  { id: 'hosp-ckm-ss-3', profileId: 'chef-kitchen-manager', categoryId: 'hosp-ckm-soft-skills', competencyId: 'hosp-ckm-brigade-leadership', type: 'scale', content: { es: '¿Qué tan efectivo se considera formando y desarrollando cocineros junior para que puedan asumir mayores responsabilidades en la brigada?', en: 'How effective do you consider yourself at training and developing junior cooks so they can take on greater responsibilities in the brigade?', fr: 'À quel point vous considérez-vous efficace pour former et développer les cuisiniers juniors afin qu\'ils puissent assumer de plus grandes responsabilités dans la brigade ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Me enfoco más en la producción que en la formación del equipo', en: 'I focus more on production than on team development', fr: 'Je me concentre davantage sur la production que sur la formation de l\'équipe' }, max: { es: 'Desarrollo activamente a mi equipo y varios de mis excocineros ahora lideran sus propias cocinas', en: 'I actively develop my team and several of my former cooks now lead their own kitchens', fr: 'Je développe activement mon équipe et plusieurs de mes anciens cuisiniers dirigent maintenant leurs propres cuisines' } }, maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  // Stress Management — scale
  { id: 'hosp-ckm-ss-4', profileId: 'chef-kitchen-manager', categoryId: 'hosp-ckm-soft-skills', competencyId: 'hosp-ckm-stress-management', type: 'scale', content: { es: '¿Cómo evalúa su capacidad para mantener un ambiente de trabajo respetuoso y profesional en la cocina, incluso bajo la presión más intensa del servicio?', en: 'How do you evaluate your ability to maintain a respectful and professional work environment in the kitchen, even under the most intense service pressure?', fr: 'Comment évaluez-vous votre capacité à maintenir un environnement de travail respectueux et professionnel en cuisine, même sous la pression la plus intense du service ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Reconozco que bajo presión a veces elevo la voz o me frustro visiblemente', en: 'I acknowledge that under pressure I sometimes raise my voice or become visibly frustrated', fr: 'Je reconnais que sous pression, j\'élève parfois la voix ou je montre ma frustration' }, max: { es: 'Mantengo un liderazgo sereno y constructivo incluso en los peores servicios', en: 'I maintain calm and constructive leadership even during the worst services', fr: 'Je maintiens un leadership serein et constructif même lors des pires services' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  // Collaboration — ranking
  { id: 'hosp-ckm-ss-5', profileId: 'chef-kitchen-manager', categoryId: 'hosp-ckm-soft-skills', competencyId: 'hosp-ckm-collaboration', type: 'ranking', content: { es: 'Ordene los siguientes aspectos de la colaboración cocina-salón por su importancia para una experiencia gastronómica exitosa:', en: 'Rank the following aspects of kitchen-dining room collaboration by their importance for a successful gastronomic experience:', fr: 'Classez les aspects suivants de la collaboration cuisine-salle par leur importance pour une expérience gastronomique réussie :' }, options: [{ id: 'a', text: { es: 'Comunicación fluida de tiempos de preparación y salida de platos', en: 'Smooth communication of preparation times and dish dispatch', fr: 'Communication fluide des temps de préparation et sortie des plats' }, value: 1 }, { id: 'b', text: { es: 'Conocimiento del menú por parte del equipo de salón (ingredientes, técnicas, alérgenos)', en: 'Menu knowledge by the dining room team (ingredients, techniques, allergens)', fr: 'Connaissance du menu par l\'équipe de salle (ingrédients, techniques, allergènes)' }, value: 2 }, { id: 'c', text: { es: 'Feedback del salón sobre comentarios y preferencias de los comensales', en: 'Dining room feedback on guest comments and preferences', fr: 'Retours de la salle sur les commentaires et préférences des convives' }, value: 3 }, { id: 'd', text: { es: 'Respeto mutuo y entendimiento de las presiones de cada equipo', en: 'Mutual respect and understanding of each team\'s pressures', fr: 'Respect mutuel et compréhension des pressions de chaque équipe' }, value: 4 }], maxScore: 100, aiEvaluated: false, order: 5, isActive: true },
  // Collaboration — open-text
  { id: 'hosp-ckm-ss-6', profileId: 'chef-kitchen-manager', categoryId: 'hosp-ckm-soft-skills', competencyId: 'hosp-ckm-collaboration', type: 'open-text', content: { es: 'El gerente del restaurante le comunica que el sommelier ha propuesto un menú de maridaje para un evento especial, pero las combinaciones de vinos contradicen su visión culinaria para varios platillos. El sommelier tiene experiencia reconocida y una relación estrecha con la dirección del hotel. Describa cómo abordaría esta diferencia de criterio profesional para llegar a un menú de maridaje que satisfaga a ambos y ofrezca una experiencia excepcional al comensal.', en: 'The restaurant manager informs you that the sommelier has proposed a pairing menu for a special event, but the wine combinations contradict your culinary vision for several dishes. The sommelier has recognized experience and a close relationship with hotel management. Describe how you would approach this professional difference of opinion to arrive at a pairing menu that satisfies both and delivers an exceptional guest experience.', fr: 'Le directeur du restaurant vous informe que le sommelier a proposé un menu de mariage mets-vins pour un événement spécial, mais les combinaisons de vins contredisent votre vision culinaire pour plusieurs plats. Le sommelier a une expérience reconnue et une relation étroite avec la direction. Décrivez comment vous aborderiez cette différence d\'opinion professionnelle pour arriver à un menu qui satisfasse les deux parties et offre une expérience exceptionnelle.' }, rubric: { es: 'Evaluar: (1) Apertura y respeto hacia la expertise del sommelier, (2) Propuesta de sesión de degustación conjunta, (3) Argumentación técnica basada en sabores y texturas, (4) Disposición a ajustar platillos si el maridaje lo justifica, (5) Enfoque en el resultado final para el comensal, (6) Construcción de una relación de colaboración a largo plazo.', en: 'Evaluate: (1) Openness and respect for the sommelier\'s expertise, (2) Proposal for a joint tasting session, (3) Technical argumentation based on flavors and textures, (4) Willingness to adjust dishes if the pairing justifies it, (5) Focus on the final result for the diner, (6) Building a long-term collaborative relationship.', fr: 'Évaluer : (1) Ouverture et respect de l\'expertise du sommelier, (2) Proposition de dégustation conjointe, (3) Argumentation technique, (4) Volonté d\'ajuster les plats, (5) Focus sur le résultat final, (6) Construction d\'une relation collaborative durable.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

