export const hospCkmReadinessQuestions: Question[] = [
  // Culinary Innovation — multiple-choice
  { id: 'hosp-ckm-rd-1', profileId: 'chef-kitchen-manager', categoryId: 'hosp-ckm-readiness', competencyId: 'hosp-ckm-culinary-innovation', type: 'multiple-choice', content: { es: 'La dirección del hotel le pide incorporar técnicas de cocina molecular a su menú para atraer un público gourmet más joven. Usted tiene formación clásica francesa y nunca ha trabajado con estas técnicas. Su equipo tampoco tiene experiencia. ¿Cuál es su enfoque?', en: 'Hotel management asks you to incorporate molecular gastronomy techniques into your menu to attract a younger gourmet audience. You have classic French training and have never worked with these techniques. Your team also has no experience. What is your approach?', fr: 'La direction de l\'hôtel vous demande d\'incorporer des techniques de gastronomie moléculaire dans votre menu pour attirer un public gourmet plus jeune. Vous avez une formation classique française et n\'avez jamais travaillé ces techniques. Votre équipe n\'a pas non plus d\'expérience. Quelle est votre approche ?' }, options: [{ id: 'a', text: { es: 'Abrazar la oportunidad de aprendizaje: investigar y tomar un curso intensivo de cocina molecular, seleccionar 3-4 técnicas que complementen su estilo clásico (esferificaciones, aires, geles), integrarlas gradualmente en platillos existentes para crear una fusión clásico-moderna, capacitar al equipo progresivamente, y hacer pruebas con grupos de enfoque antes de lanzar', en: 'Embrace the learning opportunity: research and take an intensive molecular gastronomy course, select 3-4 techniques that complement your classic style (spherification, foams, gels), gradually integrate them into existing dishes to create a classic-modern fusion, progressively train the team, and conduct focus group testing before launch', fr: 'Saisir l\'opportunité d\'apprentissage : suivre un cours intensif de gastronomie moléculaire, sélectionner 3-4 techniques complémentaires à votre style classique (sphérification, airs, gels), les intégrer graduellement dans les plats existants, former l\'équipe progressivement et tester avec des groupes de discussion avant le lancement' }, value: 100 }, { id: 'b', text: { es: 'Contratar un chef especializado en cocina molecular para que lidere esta línea del menú', en: 'Hire a chef specialized in molecular gastronomy to lead this menu line', fr: 'Embaucher un chef spécialisé en gastronomie moléculaire pour diriger cette ligne du menu' }, value: 45 }, { id: 'c', text: { es: 'Proponer una alternativa: en lugar de molecular, ofrecer una experiencia de cocina creativa contemporánea que aproveche su expertise clásica', en: 'Propose an alternative: instead of molecular, offer a contemporary creative cuisine experience that leverages your classic expertise', fr: 'Proposer une alternative : au lieu de la moléculaire, offrir une expérience de cuisine créative contemporaine qui tire parti de votre expertise classique' }, value: 50 }, { id: 'd', text: { es: 'Expresar que la cocina molecular es una moda pasajera y proponer otras formas de atraer público joven', en: 'Express that molecular gastronomy is a passing trend and propose other ways to attract young audiences', fr: 'Exprimer que la gastronomie moléculaire est une mode passagère et proposer d\'autres façons d\'attirer un public jeune' }, value: 15 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  // Kitchen Technology — multiple-choice
  { id: 'hosp-ckm-rd-2', profileId: 'chef-kitchen-manager', categoryId: 'hosp-ckm-readiness', competencyId: 'hosp-ckm-kitchen-tech', type: 'multiple-choice', content: { es: 'Le presentan un software de gestión de cocina que digitaliza: fichas técnicas de recetas, control de inventario en tiempo real, cálculo automático de food cost por platillo, programación de producción y registro HACCP digital. La inversión es de USD 15,000 anuales. Actualmente su equipo usa hojas de cálculo y registros en papel. Algunos cocineros experimentados se resisten a "usar computadoras para cocinar". ¿Cuál es su posición?', en: 'You are presented with a kitchen management software that digitizes: recipe spec sheets, real-time inventory control, automatic per-dish food cost calculation, production scheduling, and digital HACCP recording. The investment is USD 15,000 annually. Currently your team uses spreadsheets and paper records. Some experienced cooks resist "using computers to cook." What is your position?', fr: 'On vous présente un logiciel de gestion de cuisine qui numérise : fiches techniques de recettes, contrôle d\'inventaire en temps réel, calcul automatique du food cost par plat, planification de production et enregistrement HACCP numérique. L\'investissement est de 15 000 USD par an. Actuellement, votre équipe utilise des tableurs et des registres papier. Certains cuisiniers expérimentés résistent à "utiliser des ordinateurs pour cuisiner." Quelle est votre position ?' }, options: [{ id: 'a', text: { es: 'Apoyar la adopción con un plan de implementación gradual: comenzar con fichas técnicas digitales y HACCP (beneficio inmediato de cumplimiento), capacitar al equipo en fases empezando por los más receptivos, demostrar los beneficios con resultados concretos (ahorro de tiempo, reducción de errores), y eventualmente migrar todo el sistema', en: 'Support adoption with a gradual implementation plan: start with digital spec sheets and HACCP (immediate compliance benefit), train the team in phases starting with the most receptive, demonstrate benefits with concrete results (time savings, error reduction), and eventually migrate the entire system', fr: 'Soutenir l\'adoption avec un plan de mise en œuvre graduel : commencer par les fiches techniques numériques et le HACCP, former l\'équipe par phases en commençant par les plus réceptifs, démontrer les bénéfices avec des résultats concrets et éventuellement migrer tout le système' }, value: 100 }, { id: 'b', text: { es: 'Implementar todo el sistema de inmediato y exigir que todos lo usen', en: 'Implement the entire system immediately and require everyone to use it', fr: 'Mettre en œuvre tout le système immédiatement et exiger que tout le monde l\'utilise' }, value: 30 }, { id: 'c', text: { es: 'Rechazar el software porque la cocina requiere tacto humano y las herramientas actuales funcionan', en: 'Reject the software because cooking requires human touch and current tools work', fr: 'Rejeter le logiciel car la cuisine nécessite un toucher humain et les outils actuels fonctionnent' }, value: 10 }, { id: 'd', text: { es: 'Asignar la gestión del software solo al sous chef y al encargado de compras', en: 'Assign software management only to the sous chef and purchasing manager', fr: 'Attribuer la gestion du logiciel uniquement au sous-chef et au responsable des achats' }, value: 35 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  // Culinary Innovation — scale
  { id: 'hosp-ckm-rd-3', profileId: 'chef-kitchen-manager', categoryId: 'hosp-ckm-readiness', competencyId: 'hosp-ckm-culinary-innovation', type: 'scale', content: { es: '¿Qué tan abierto está a experimentar con ingredientes, técnicas y estilos de cocina fuera de su zona de confort o formación original?', en: 'How open are you to experimenting with ingredients, techniques, and cooking styles outside your comfort zone or original training?', fr: 'À quel point êtes-vous ouvert à expérimenter avec des ingrédients, techniques et styles de cuisine en dehors de votre zone de confort ou formation originale ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Prefiero perfeccionar lo que ya domino', en: 'I prefer to perfect what I already master', fr: 'Je préfère perfectionner ce que je maîtrise déjà' }, max: { es: 'Constantemente busco aprender técnicas nuevas y explorar cocinas desconocidas', en: 'I constantly seek to learn new techniques and explore unfamiliar cuisines', fr: 'Je cherche constamment à apprendre de nouvelles techniques et explorer des cuisines inconnues' } }, maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  // Sustainable Cooking — scale
  { id: 'hosp-ckm-rd-4', profileId: 'chef-kitchen-manager', categoryId: 'hosp-ckm-readiness', competencyId: 'hosp-ckm-sustainable-cooking', type: 'scale', content: { es: '¿En qué medida ha incorporado prácticas de cocina sostenible en su trabajo (aprovechamiento integral de ingredientes, reducción de desperdicio, productos locales y estacionales)?', en: 'To what extent have you incorporated sustainable cooking practices in your work (whole-ingredient usage, waste reduction, local and seasonal products)?', fr: 'Dans quelle mesure avez-vous intégré des pratiques de cuisine durable dans votre travail (utilisation intégrale des ingrédients, réduction du gaspillage, produits locaux et de saison) ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'No he trabajado específicamente con enfoque de sostenibilidad', en: 'I have not specifically worked with a sustainability focus', fr: 'Je n\'ai pas spécifiquement travaillé avec un focus sur la durabilité' }, max: { es: 'La sostenibilidad es un pilar fundamental de mi filosofía culinaria', en: 'Sustainability is a fundamental pillar of my culinary philosophy', fr: 'La durabilité est un pilier fondamental de ma philosophie culinaire' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  // Kitchen Technology — scenario
  { id: 'hosp-ckm-rd-5', profileId: 'chef-kitchen-manager', categoryId: 'hosp-ckm-readiness', competencyId: 'hosp-ckm-kitchen-tech', type: 'scenario', content: { es: 'El hotel está considerando incorporar un robot de cocina automatizado que puede realizar tareas repetitivas: cortar vegetales uniformemente, preparar bases de salsas, medir y pesar ingredientes, y monitorear cocciones con sensores de temperatura. El costo es de USD 60,000 y reemplazaría la labor equivalente a 1.5 cocineros preparadores. Su brigada actual es de 10 personas. Varios cocineros expresan temor de ser reemplazados.\nContexto: El hotel busca reducir costos operativos un 8% este año. La rotación de personal en cocina es del 50% anual. Los costos de capacitación de nuevos cocineros son USD 5,000 por persona.', en: 'The hotel is considering incorporating an automated kitchen robot that can perform repetitive tasks: uniformly cut vegetables, prepare sauce bases, measure and weigh ingredients, and monitor cooking with temperature sensors. The cost is USD 60,000 and would replace the work equivalent of 1.5 prep cooks. Your current brigade is 10 people. Several cooks express fear of being replaced.\nContext: The hotel seeks to reduce operating costs by 8% this year. Kitchen staff turnover is 50% annually. Training costs for new cooks are USD 5,000 per person.', fr: 'L\'hôtel envisage d\'incorporer un robot de cuisine automatisé pouvant effectuer des tâches répétitives. Le coût est de 60 000 USD et remplacerait le travail équivalent à 1,5 cuisiniers préparateurs. Votre brigade actuelle est de 10 personnes. Plusieurs cuisiniers craignent d\'être remplacés.\nContexte : L\'hôtel cherche à réduire les coûts de 8%. La rotation du personnel en cuisine est de 50% par an. Le coût de formation est de 5 000 USD par personne.' }, rubric: { es: 'Evaluar: (1) Análisis objetivo del ROI (robot vs. costos de rotación y capacitación), (2) Visión de la tecnología como complemento, no reemplazo, del talento humano, (3) Plan para reasignar a los cocineros preparadores a roles de mayor valor, (4) Comunicación transparente con el equipo, (5) Implementación gradual con período de prueba, (6) Evaluación de impacto en calidad y consistencia.', en: 'Evaluate: (1) Objective ROI analysis (robot vs. turnover and training costs), (2) Vision of technology as complement, not replacement, of human talent, (3) Plan to reassign prep cooks to higher-value roles, (4) Transparent communication with the team, (5) Gradual implementation with trial period, (6) Quality and consistency impact evaluation.', fr: 'Évaluer : (1) Analyse objective du ROI, (2) Vision de la technologie comme complément du talent humain, (3) Plan de réaffectation des cuisiniers, (4) Communication transparente, (5) Mise en œuvre graduelle, (6) Évaluation de l\'impact sur la qualité.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  // Sustainable Cooking — open-text
  { id: 'hosp-ckm-rd-6', profileId: 'chef-kitchen-manager', categoryId: 'hosp-ckm-readiness', competencyId: 'hosp-ckm-sustainable-cooking', type: 'open-text', content: { es: 'El hotel le solicita crear un concepto de menú "Farm-to-Table" (de la granja a la mesa) que utilice al menos un 70% de ingredientes de productores locales ubicados en un radio de 100 km. Actualmente, solo el 15% de sus ingredientes son locales. Describa cómo transformaría su menú, cadena de abastecimiento y operación de cocina para lograr este objetivo, incluyendo los desafíos que anticipa y cómo los resolvería.', en: 'The hotel asks you to create a "Farm-to-Table" menu concept that uses at least 70% ingredients from local producers within a 100 km radius. Currently, only 15% of your ingredients are local. Describe how you would transform your menu, supply chain, and kitchen operation to achieve this goal, including the challenges you anticipate and how you would resolve them.', fr: 'L\'hôtel vous demande de créer un concept de menu "Farm-to-Table" utilisant au moins 70% d\'ingrédients de producteurs locaux dans un rayon de 100 km. Actuellement, seulement 15% de vos ingrédients sont locaux. Décrivez comment vous transformeriez votre menu, chaîne d\'approvisionnement et opération de cuisine pour atteindre cet objectif, incluant les défis anticipés et comment les résoudre.' }, rubric: { es: 'Evaluar: (1) Investigación y mapeo de productores locales, (2) Diseño de menú estacional y flexible basado en disponibilidad local, (3) Estrategia de transición gradual de proveedores, (4) Gestión de los desafíos: consistencia, volumen, precio, estacionalidad, (5) Valor agregado para el huésped (storytelling, trazabilidad, experiencias en granja), (6) Métricas de seguimiento y plan de comunicación interna y externa.', en: 'Evaluate: (1) Research and mapping of local producers, (2) Seasonal and flexible menu design based on local availability, (3) Gradual supplier transition strategy, (4) Challenge management: consistency, volume, price, seasonality, (5) Added value for the guest (storytelling, traceability, farm experiences), (6) Tracking metrics and internal/external communication plan.', fr: 'Évaluer : (1) Recherche et cartographie des producteurs locaux, (2) Conception de menu saisonnier et flexible, (3) Stratégie de transition graduelle des fournisseurs, (4) Gestion des défis, (5) Valeur ajoutée pour le client, (6) Métriques de suivi et plan de communication.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];
